const CARDS = [{"id": "nh_readme", "character": "README.md", "scenario": "The README says 'setup should take 30 minutes.' It's been **4 hours**. You're mass-installing Python 2.7 dependencies. The last commit was 9 months ago.", "leftOption": {"label": "Ask for help like a noob", "effects": {"reputation": -3, "sanity": 5}, "hiddenConsequences": null, "roast": "Admitting you can't set up a repo from 2019. Your TC negotiation leverage just evaporated."}, "rightOption": {"label": "Suffer in silence for the TC", "effects": {"sanity": -4, "reputation": 5}, "hiddenConsequences": null, "roast": "4 hours into a dead repo and you're calling it 'grit.' That's not hustle, that's Stockholm syndrome."}, "minStage": "newHire", "maxStage": "newHire", "isTutorial": false}, {"id": "nh_laptop", "character": "IT Support", "scenario": "IT hands you a **2019 MacBook Pro** with a butterfly keyboard. '**Budget's tight** after the last round of layoffs.' Your TC could buy 47 of these.", "leftOption": {"label": "Accept like a good little IC", "effects": {"sanity": 0, "stability": 1, "tc": 4}, "hiddenConsequences": null, "roast": "Butterfly keyboard and $400K TC. You're living the dream."}, "rightOption": {"label": "Escalate (career-limiting move)", "effects": {"reputation": -3, "stability": -3, "sanity": 3, "tc": -3}, "hiddenConsequences": null, "roast": "Escalating about a laptop on Day 1. HR already has a note in your file."}, "minStage": "newHire", "maxStage": "newHire", "isTutorial": false}, {"id": "nh_lunch_tc", "character": "Buddy", "scenario": "Your onboarding buddy takes you to lunch. 5 minutes in: 'So... **what's your TC?** Level? RSU split? Sign-on cliff?' TC or GTFO energy.", "leftOption": {"label": "\"I'd rather not say\"", "effects": {"reputation": -2, "tc": -3}, "hiddenConsequences": null, "roast": "Refusing to share TC is how people assume you're underpaid. They're probably right."}, "rightOption": {"label": "Drop the full breakdown", "effects": {"reputation": 8, "stability": -3, "tc": 4}, "hiddenConsequences": [{"effects": {"reputation": -5}, "description": "Your TC is now public knowledge. Half the team thinks you're overpaid. The other half is updating their resumes.", "delay": 4}], "roast": "Sharing your full comp breakdown to a stranger on Day 1. Blind would be proud."}, "minStage": "newHire", "maxStage": "ramping", "isTutorial": false}, {"id": "nh_standup", "character": "Scrum Master", "scenario": "First standup. Everyone rattles off updates in exactly 30 seconds like **corporate NPCs**. Your turn. You haven't done anything because your laptop can't run the repo.", "leftOption": {"label": "Ramble for 2 minutes about Docker", "effects": {"sanity": -2, "reputation": -3, "tc": 3}, "hiddenConsequences": null, "roast": "Nobody understood a word you said but at least you sounded busy. Classic new hire cope."}, "rightOption": {"label": "\"No blockers\" (cope)", "effects": {"reputation": 3}, "hiddenConsequences": [{"effects": {"stability": -3}, "description": "You definitely had blockers. Your first ticket is now 3 sprints late. Manager is 'concerned about ramp velocity.'", "delay": 3}], "roast": "'No blockers' is the corporate equivalent of 'I'm fine.' Everyone knows you're drowning."}, "minStage": "newHire", "maxStage": "ramping", "isTutorial": false}, {"id": "nh_ci_broken", "character": "#general", "scenario": "Someone posts in #general: '**Is CI broken** or is it just me?' Three staff engineers reply '**works on my machine.**' It does not work on your machine.", "leftOption": {"label": "Mute the channel", "effects": {"sanity": -2, "stability": 2}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "CI was broken for a week. Your PR queue is backed up. Your manager thinks you're slacking. You're one sprint from being 'managed out.'", "delay": 5}], "roast": "Muting CI alerts on your first week. You'll fit right in with the rest-and-vest crowd."}, "rightOption": {"label": "Debug it (masochist arc)", "effects": {"reputation": 5, "sanity": -4}, "hiddenConsequences": null, "roast": "Debugging someone else's broken pipeline for free. Unpaid labor speedrun any%."}, "minStage": "newHire", "maxStage": "contributing", "isTutorial": false}, {"id": "nh_badge_photo", "character": "Security Desk", "scenario": "Badge photo time. The fluorescent lighting makes you look like you've been coding for 30 years. This photo will **haunt every internal directory** for your entire tenure.", "leftOption": {"label": "Ask for a retake", "effects": {"reputation": -2, "sanity": 3}, "hiddenConsequences": null, "roast": "Requesting a badge photo retake on Day 1. The security guard has seen things. You are not special."}, "rightOption": {"label": "Accept your fate", "effects": {"sanity": -1}, "hiddenConsequences": null, "roast": "That badge photo will be your professional identity for the next 4 years. You look like a mugshot."}, "minStage": "newHire", "maxStage": "newHire", "isTutorial": false}, {"id": "nh_onboarding_video", "character": "HR Portal", "scenario": "14 hours of mandatory compliance training. Anti-harassment. Data privacy. Ergonomics. **You must score 100% on every quiz.** The videos auto-pause if you switch tabs.", "leftOption": {"label": "Actually watch them all", "effects": {"sanity": -7, "stability": 5, "tc": 3}, "hiddenConsequences": null, "roast": "You watched 14 hours of compliance videos at 1x speed. You'll never get those brain cells back."}, "rightOption": {"label": "Speed through at 2x", "effects": {"sanity": 3, "tc": -3}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "You failed the data privacy quiz. HR flagged you. Your manager got an email. Great first impression.", "delay": 2}], "roast": "2x speed on compliance training. You absorbed nothing but at least you have time to doomscroll Blind."}, "minStage": "newHire", "maxStage": "newHire", "isTutorial": false}, {"id": "nh_slack_intro", "character": "Slack #general", "scenario": "Time for the **dreaded new hire intro post**. Everyone else's was 3 paragraphs with fun facts and hobbies. You have no hobbies. Your fun fact is your TC.", "leftOption": {"label": "\"Hi, excited to be here!\" (boring)", "effects": {"reputation": -2, "tc": 3}, "hiddenConsequences": null, "roast": "'Excited to be here!' \u2014 the corporate equivalent of 'I'm fine.' Zero personality detected."}, "rightOption": {"label": "Go full try-hard with puns", "effects": {"reputation": 5, "sanity": -1, "tc": -3}, "hiddenConsequences": null, "roast": "Your intro post has 3 puns and a meme. Half the team thinks you're hilarious. The other half muted the channel."}, "minStage": "newHire", "maxStage": "newHire", "isTutorial": false}, {"id": "nh_meeting_overload", "character": "Google Calendar", "scenario": "Day 3. Your calendar is already **80% meetings**. Onboarding sync. Team sync. Skip-level. Coffee chat. 'Culture fit' chat. You have 45 minutes to actually code.", "leftOption": {"label": "Decline half (bold move)", "effects": {"reputation": -5, "sanity": 5}, "hiddenConsequences": null, "roast": "Declining meetings on Day 3. Your manager's calendar notification just pinged."}, "rightOption": {"label": "Accept everything (people pleaser)", "effects": {"sanity": -4, "stability": 3}, "hiddenConsequences": null, "roast": "You accepted every meeting invite like a golden retriever. You'll learn nothing and ship nothing but everyone likes you."}, "minStage": "newHire", "maxStage": "newHire", "isTutorial": false}, {"id": "nh_codebase_archaeology", "character": "Git Blame", "scenario": "The function you need to change has **no comments, no tests, and the last author left 2 years ago**. Git blame shows 47 contributors. The variable is called `temp2_final_v3`.", "leftOption": {"label": "Rewrite from scratch (hubris)", "effects": {"reputation": -3, "sanity": 5}, "hiddenConsequences": [{"effects": {"stability": -8}, "description": "Your rewrite broke 3 downstream services. Turns out temp2_final_v3 was load-bearing. The original author was right.", "delay": 3}], "roast": "Rewriting code you don't understand. The Dunning-Kruger is strong with this one."}, "rightOption": {"label": "Patch around it carefully", "effects": {"sanity": -4, "reputation": 3}, "hiddenConsequences": null, "roast": "Adding another layer to the archaeological dig. Future engineers will blame YOU in git blame."}, "minStage": "newHire", "maxStage": "ramping", "isTutorial": false}, {"id": "ramp_first_pr", "character": "Tech Lead", "scenario": "First PR: **47 comments**. Zero about logic. 'nit: trailing whitespace.' 'nit: prefer const.' 'nit: I would name this differently.' This is what **$400K TC** buys you.", "leftOption": {"label": "Address every nit like a simp", "effects": {"sanity": -4, "reputation": 5, "tc": 3}, "hiddenConsequences": null, "roast": "Addressing every nit like your career depends on it. Spoiler: it doesn't."}, "rightOption": {"label": "\"Will fix in follow-up\" (you won't)", "effects": {"stability": -3, "tc": -3}, "hiddenConsequences": [{"effects": {"stability": -5, "reputation": -3}, "description": "That 'follow-up' PR never happened. The tech debt caused a P0. Your LGTM is in the incident timeline. URA material.", "delay": 5}], "roast": "'Will fix in follow-up' \u2014 the tech debt creation myth that keeps on giving."}, "minStage": "ramping", "maxStage": "contributing", "isTutorial": false}, {"id": "ramp_oncall", "character": "PagerDuty", "scenario": "**3 AM.** PagerDuty screams. 'CRITICAL: Production database CPU at 98%.' This is what WLB looks like at your company.", "leftOption": {"label": "Ignore it, rest and vest", "effects": {"sanity": -2}, "hiddenConsequences": [{"effects": {"stability": -8, "reputation": -5}, "description": "It did not fix itself. The incident report mentions you by name. Twice. Your manager cc'd their manager. PIP vibes.", "delay": 3}], "roast": "Ignoring pages during ramp. Bold strategy for someone whose RSUs haven't vested yet."}, "rightOption": {"label": "Wake up (golden handcuffs require it)", "effects": {"sanity": -7, "reputation": 8}, "hiddenConsequences": null, "roast": "Waking up at 3 AM for a service you don't understand. The golden handcuffs are working."}, "minStage": "ramping", "maxStage": "senior", "isTutorial": false}, {"id": "ramp_feedback", "character": "Manager", "scenario": "1:1 with your manager. '**You're doing great, but...**' The 'but' lingers like a layoff rumor on Blind. Your palms are sweating.", "leftOption": {"label": "\"Can you be specific?\"", "effects": {"sanity": -2, "reputation": 5}, "hiddenConsequences": null, "roast": "Asking for specific feedback is how you find out your manager doesn't have any."}, "rightOption": {"label": "\"Thanks!\" (cope and dissociate)", "effects": {"sanity": -2, "stability": 2}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "That vague feedback metastasized. Showed up in your perf review as 'not receptive to coaching.' One step closer to being managed out.", "delay": 5}], "roast": "Saying 'thanks' to vague criticism. The corporate gaslighting pipeline is working perfectly."}, "minStage": "ramping", "maxStage": "contributing", "isTutorial": false}, {"id": "ramp_allhands", "character": "CEO", "scenario": "All-hands. CEO presenting Q3 results. **Slide 12 of 97.** Revenue is 'not where we want it' but the '**AI strategy is exciting.**' You can feel the layoffs coming.", "leftOption": {"label": "Zone out, open Blind", "effects": {"sanity": -2, "stability": 2}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "You missed the reorg announcement on slide 84. Your team got dissolved. Everyone else already updated their Blind profiles.", "delay": 4}], "roast": "Scrolling Blind during all-hands is how you end up ON Blind."}, "rightOption": {"label": "Pay attention (masochist)", "effects": {"sanity": -1, "stability": -5}, "hiddenConsequences": null, "roast": "Actually paying attention to the CEO? That's not dedication, that's a cry for help."}, "minStage": "ramping", "maxStage": "staff", "isTutorial": false}, {"id": "ramp_deploy_friday", "character": "Slack Bot", "scenario": "**Friday 4 PM.** PR approved. The deploy button glows. Your WLB depends on the next 3 seconds.", "leftOption": {"label": "Deploy Monday (cope)", "effects": {"sanity": 5, "reputation": -2}, "hiddenConsequences": null, "roast": "Deploying Monday is just admitting you don't trust your own code. Smart, actually."}, "rightOption": {"label": "YOLO deploy, TGIF", "effects": {"reputation": 5, "sanity": -2}, "hiddenConsequences": [{"effects": {"sanity": -8, "stability": -5}, "description": "Friday deploy nuked prod. You spent your weekend in a war room. WLB is cope. Your TC per hour worked is now below minimum wage.", "delay": 1}], "roast": "YOLO Friday deploy. Your oncall teammate is already drafting their resignation."}, "minStage": "ramping", "maxStage": "senior", "isTutorial": false}, {"id": "ramp_lgtm", "character": "Coworker", "scenario": "Coworker drops an **800-line PR** in your review queue. 'Should be straightforward.' It touches auth, payments, and the database schema. **Zero tests.**", "leftOption": {"label": "Actually review it (RIP your afternoon)", "effects": {"sanity": -4, "reputation": 5, "tc": -3}, "hiddenConsequences": null, "roast": "Actually reading the diff like some kind of engineer. Your afternoon died for nothing."}, "rightOption": {"label": "LGTM ship it", "effects": {"sanity": -2, "stability": 2, "tc": 4}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "That 800-line PR introduced a critical auth bypass. Your 'LGTM' is screenshot'd in the incident Slack. Trust me bro, this is bad.", "delay": 4}, {"effects": {"reputation": -5}, "description": "'Your LGTM culture will be discussed in your performance review.' Direct quote from your manager.", "delay": 5}], "roast": "LGTM without reading. You just mass-approved someone's tech debt monument."}, "minStage": "ramping", "maxStage": "senior", "isTutorial": false}, {"id": "contrib_sprint", "character": "Product Manager", "scenario": "PM wants to cram **3 more tickets** into the sprint. It's Wednesday. The sprint ends Friday. '**They're small, I promise.**' They are not small.", "leftOption": {"label": "Push back (career-limiting honesty)", "effects": {"reputation": -3, "sanity": 5}, "hiddenConsequences": null, "roast": "Pushing back on scope? In this economy? Bold move for someone mid-cliff."}, "rightOption": {"label": "Accept the scope creep like cattle", "effects": {"sanity": -4, "stability": 5}, "hiddenConsequences": [{"effects": {"sanity": -5}, "description": "Worked the entire weekend for those 3 tickets. PM didn't notice. Your Blind post 'Is $X TC worth this?' got 200 upvotes.", "delay": 2}], "roast": "Accepting scope creep without protest. Your burnout is now a team sport."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false}, {"id": "contrib_promo", "character": "Manager", "scenario": "Manager mentions **promo packets are due in 6 weeks**. 'You should start writing yours.' Translation: document why you deserve to go from peanuts to slightly bigger peanuts.", "leftOption": {"label": "Start the promo doc grind", "effects": {"sanity": -2, "reputation": 8}, "hiddenConsequences": null, "roast": "Starting the promo doc grind. Welcome to the real job: writing about your job."}, "rightOption": {"label": "\"I'll get to it\" (you won't)", "effects": {"sanity": -2, "stability": 2}, "hiddenConsequences": [{"effects": {"reputation": -8, "tc": -5}, "description": "Promo denied. 'Not enough documented impact.' Refresher grant: $0. Meanwhile the guy who wrote the promo doc got upleveled. That's cope? No, that's reality.", "delay": 5}], "roast": "'I'll get to it' \u2014 narrator: they never got to it. Enjoy L4 forever."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false}, {"id": "contrib_peer_review", "character": "HR System", "scenario": "Peer review time. You're asked to review someone you've **literally never spoken to**. Their Slack avatar is a default silhouette. You're not sure they still work here.", "leftOption": {"label": "Write generic corporate fluff", "effects": {"sanity": -2, "stability": 2}, "hiddenConsequences": [{"effects": {"reputation": -5}, "description": "They wrote you a brutally specific review back. Cited exact PRs. Quoted your Slack messages. They were watching you the whole time.", "delay": 5}], "roast": "Generic corporate fluff in a peer review. You just described a potted plant as 'a strong collaborator.'"}, "rightOption": {"label": "\"I don't know this person\"", "effects": {"reputation": -3, "sanity": 5}, "hiddenConsequences": null, "roast": "Admitting you don't know your teammate. At least you're honest about the dysfunction."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false}, {"id": "contrib_recruiter_dm", "character": "LinkedIn", "scenario": "Recruiter DM: 'Hi!! I have an **AMAZING opportunity** at a pre-IPO startup. 40% TC bump, unlimited PTO, and a **ping pong table.**' Red flags everywhere.", "leftOption": {"label": "Ignore (golden handcuffs too tight)", "effects": {"sanity": -2}, "hiddenConsequences": null, "roast": "Ignoring a recruiter DM while complaining about TC on Blind. The cognitive dissonance is chef's kiss."}, "rightOption": {"label": "Take the call (TC or GTFO)", "effects": {"tc": 8, "stability": -5}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Your manager heard you're interviewing. You're now on the 'flight risk' list. Next reorg, you're getting managed out.", "delay": 4}], "roast": "Taking the recruiter call during work hours. Your manager's calendar just got a 'flight risk' tag."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false}, {"id": "contrib_bestie_leaves", "character": "Work Bestie", "scenario": "Work bestie just accepted at Stripe. '**Couldn't say no to the TC**, honestly.' They show you the offer letter. It's obscene. Your golden handcuffs just got tighter.", "leftOption": {"label": "\"I'm happy for you\" (lie)", "effects": {"sanity": -4, "stability": -3, "tc": 3}, "hiddenConsequences": null, "roast": "'Happy for you' while dying inside. That's not friendship, that's corporate trauma bonding."}, "rightOption": {"label": "Rage-update your LinkedIn", "effects": {"sanity": -2, "stability": -3, "reputation": 3}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Three teammates noticed your LinkedIn update. The rumor mill on Blind is already spinning. 'Heard someone on [your team] is jumping ship.'", "delay": 3}], "roast": "Rage-updating LinkedIn after your friend leaves. Nothing says 'I'm fine' like a new headshot."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false}, {"id": "contrib_team_exodus", "character": "Slack", "scenario": "**3 people quit** your team this month. You're now the most senior engineer by default. Congrats on your **battlefield promotion**. TC stays the same btw.", "leftOption": {"label": "Step up (free labor for promo packet)", "effects": {"reputation": 8, "sanity": -4, "stability": -3, "tc": 2}, "hiddenConsequences": null, "roast": "Stepping up during an exodus for 'promo material.' You're doing 3 jobs for the price of 1."}, "rightOption": {"label": "Rest and vest, not my problem", "effects": {"reputation": -3, "sanity": -2, "stability": 3}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Manager noted 'lack of leadership initiative.' Translation: you're now bottom of the stack rank. PIP incoming.", "delay": 4}], "roast": "Rest and vest while the ship sinks. At least you'll be well-rested when the PIP hits."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false}, {"id": "contrib_legacy_owner", "character": "Coworker", "scenario": "The only person who understood the **legacy payments system** just gave 2 weeks notice. They're going to a FAANG competitor to rest and vest. **Zero documentation** exists.", "leftOption": {"label": "Beg them to stay (desperate)", "effects": {"reputation": -3, "sanity": -2, "tc": 3}, "hiddenConsequences": null, "roast": "Begging someone to stay for their legacy code knowledge. Down bad for a COBOL maintainer."}, "rightOption": {"label": "Let them go (inherit the nightmare)", "effects": {"stability": -8, "reputation": 5, "tc": -3}, "hiddenConsequences": [{"effects": {"sanity": -8}, "description": "You now own a legacy system with zero docs, a framework from 2014, and it processes 40% of revenue. Your TC doesn't cover this level of suffering.", "delay": 3}], "roast": "Letting the legacy owner leave. Congrats, you just inherited a codebase with zero docs and 47 TODOs."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false}, {"id": "contrib_blind_poll", "character": "Blind", "scenario": "Lunchtime Blind check. Someone with a verified badge at your company posted: '**Layoffs next month. 30% cut.** Trust me bro.' 847 upvotes. Your stomach drops.", "leftOption": {"label": "Panic-apply to 20 companies", "effects": {"sanity": -4, "stability": -3, "tc": 3}, "hiddenConsequences": null, "roast": "Panic-applying to 20 companies because of a Blind poll. That's not due diligence, that's anxiety."}, "rightOption": {"label": "\"That's cope\" (dismiss it)", "effects": {"sanity": 3}, "hiddenConsequences": null, "roast": "Dismissing a Blind poll as cope. That's exactly what the last round of layoffs said too."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false}, {"id": "contrib_linkedin_cringe", "character": "LinkedIn", "scenario": "Your CEO posts: 'I had to **let go of 200 incredible humans** today. This was the hardest decision of my life. I cried in the shower. #leadership #grateful #humbled' **Stock is up 8%.**", "leftOption": {"label": "Like the post (sell your soul)", "effects": {"sanity": -1, "stability": -5, "reputation": 5, "tc": 3}, "hiddenConsequences": null, "roast": "Liking your CEO's LinkedIn post. Your dignity left the chat."}, "rightOption": {"label": "Screenshot to Blind with 'mass'", "effects": {"sanity": 8, "stability": -3, "reputation": -5, "tc": -3}, "hiddenConsequences": null, "roast": "Screenshotting it to Blind with 'mass.' You're the content now."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "sr_reorg_email", "character": "CEO", "scenario": "Email from CEO: '**Exciting changes ahead!**' In corporate, 'exciting' means someone's getting fired. Your fight-or-flight kicks in before you even open it.", "leftOption": {"label": "Read it now (rip the band-aid)", "effects": {"sanity": -4, "stability": -5}, "hiddenConsequences": null, "roast": "Reading the reorg email immediately. The anxiety won but at least you know your new skip-level's name."}, "rightOption": {"label": "Read after lunch (cope)", "effects": {"sanity": -2, "stability": -8, "reputation": 3}, "hiddenConsequences": null, "roast": "Postponing the reorg email until after lunch. The org chart changed twice while you ate."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "sr_new_manager", "character": "HR", "scenario": "Your team got merged. New manager starts Monday. Their LinkedIn says '**Servant Leader | Ex-Consultant | MBA.**' They've never managed engineers. **0 YOE in tech.**", "leftOption": {"label": "Give them a chance (cope)", "effects": {"sanity": -2, "stability": -5}, "hiddenConsequences": [{"effects": {"sanity": -5}, "description": "New manager scheduled daily 1-hour 'alignment syncs.' It's week 3. They still don't know what an API is. You're being managed out slowly.", "delay": 3}], "roast": "Giving the new manager a chance is just delaying the inevitable Blind post."}, "rightOption": {"label": "Request transfer immediately", "effects": {"stability": -8, "reputation": -3, "sanity": 3}, "hiddenConsequences": null, "roast": "Requesting a transfer before they even start. Your reputation as 'difficult' is now canon."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false, "excludes": ["blind_pip", "boost_good_review", "boost_spot_bonus", "credit_thief", "life_good_1on1", "life_manager_quits", "meta_perf_rating", "ramp_feedback", "sr_stack_rank"]}, {"id": "sr_design_doc", "character": "Staff Engineer", "scenario": "You spent 3 weeks on a design doc. A Staff engineer who **hasn't shipped code in 2 years** comments: '**Have you considered a completely different approach?**' 15 YOE energy.", "leftOption": {"label": "Defend your design (risky)", "effects": {"reputation": -3, "sanity": -2}, "hiddenConsequences": [{"effects": {"reputation": 10}, "description": "You won the design review. The Staff engineer respects the pushback. Power move. Promo packet material.", "delay": 2}], "roast": "Defending your design in a room full of senior engineers. Brave. Stupid, but brave."}, "rightOption": {"label": "Rewrite everything (simp behavior)", "effects": {"sanity": -7, "reputation": 5}, "hiddenConsequences": null, "roast": "Rewriting your entire design because someone left one comment. Simp behavior confirmed."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false}, {"id": "sr_rsu_cliff", "character": "E*Trade", "scenario": "1-year cliff just passed. RSUs vested. You check the stock price... **down 40%**. Your TC on Blind is now a lie. The golden handcuffs are made of tin.", "leftOption": {"label": "Sell immediately (lock in the L)", "effects": {"tc": -8, "sanity": -2, "stability": 3}, "hiddenConsequences": null, "roast": "Selling at the cliff. You just locked in losses that would make r/wallstreetbets proud."}, "rightOption": {"label": "Diamond hands (copium)", "effects": {"tc": -3, "sanity": -4, "reputation": 3}, "hiddenConsequences": [{"effects": {"tc": -5}, "description": "Stock dropped another 20%. Your diamond hands are cubic zirconia. Your Blind TC post aged like milk. Peanuts.", "delay": 5}], "roast": "Diamond hands on RSUs. Copium is not a financial strategy."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false}, {"id": "sr_tech_lead", "character": "Manager", "scenario": "Manager asks if you want to be tech lead. 'Great for your **promo packet**.' Translation: own every incident, attend every meeting, write zero code. **Same TC.**", "leftOption": {"label": "Accept (sacrifice your soul)", "effects": {"reputation": 8, "sanity": -4, "tc": 2}, "hiddenConsequences": [{"effects": {"sanity": -5, "stability": -3}, "description": "As tech lead, you own every P0. 3 incidents this week. You haven't written code in a month. Your TC per line of code is technically infinite.", "delay": 4}], "roast": "Accepting tech lead for the same TC. You just bought a title and sold your weekends."}, "rightOption": {"label": "Decline (rest and vest)", "effects": {"reputation": -5}, "hiddenConsequences": [{"effects": {"reputation": -5}, "description": "'Not showing leadership potential.' Welcome to the bottom of the stack rank. Refresher grant: peanuts.", "delay": 5}], "roast": "Declining tech lead to rest and vest. Based, but your promo packet just got thinner."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false}, {"id": "sr_counter_offer", "character": "Recruiter", "scenario": "Competing offer: **30% TC bump**. Your company wants to counter. Manager suddenly remembers you exist. '**We always valued you.**' Sure bro.", "leftOption": {"label": "Take the counter (devil you know)", "effects": {"tc": 8, "stability": 5, "reputation": -3, "sanity": 2}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Manager knows you almost bounced. You're on the 'flight risk' list. Next reorg, you're URA \u2014 unregretted attrition.", "delay": 5}, {"effects": {"reputation": -5}, "description": "Word got out you leveraged an offer. Blind post: 'Someone on my team counter-offered, is this mass behavior?' Yes.", "delay": 3}], "roast": "Taking the counter offer. Statistically, you'll leave within 6 months anyway."}, "rightOption": {"label": "Leave for the bag", "effects": {"tc": 8, "stability": -8, "sanity": 8, "reputation": 0}, "hiddenConsequences": null, "roast": "Leaving for the bag. Hope the new place's Blind reviews aren't cope."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false}, {"id": "sr_mentoring", "character": "New Hire", "scenario": "A new hire asks you to mentor them. They have **47 questions**, a doc of 'things I want to learn,' and more enthusiasm than your entire team combined. It's exhausting.", "leftOption": {"label": "Accept (free promo packet material)", "effects": {"sanity": -4, "reputation": 8}, "hiddenConsequences": null, "roast": "Mentoring for 'promo packet material.' Using junior engineers as career stepping stones. Classic."}, "rightOption": {"label": "\"I'm pretty heads down\" (lie)", "effects": {"reputation": -3}, "hiddenConsequences": null, "roast": "'Heads down' is senior-speak for 'I refuse to do anything that doesn't directly benefit my TC.'"}, "minStage": "senior", "maxStage": "staff", "isTutorial": false}, {"id": "sr_stack_rank", "character": "Manager", "scenario": "Stack ranking season. Your manager asks **who the lowest performer is**. They already have someone in mind. This is how people get PIP'd. **Corporate Hunger Games.**", "leftOption": {"label": "Agree with their pick (sellout)", "effects": {"stability": -8, "sanity": -1}, "hiddenConsequences": [{"effects": {"sanity": -5}, "description": "The person you threw under the bus got PIP'd. They found out. Posted on Blind: 'Someone on my team backstabbed me during calibration.' 2000 upvotes. It's you.", "delay": 4}], "roast": "Agreeing with the stack rank pick to keep the peace. Your integrity has a price and it's one promo cycle."}, "rightOption": {"label": "Refuse (career-limiting integrity)", "effects": {"stability": -5, "reputation": -3, "sanity": 5}, "hiddenConsequences": null, "roast": "Refusing to stack rank. Noble, but your manager just mentally stack-ranked YOU lower."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false, "excludes": ["boost_good_review", "boost_spot_bonus", "life_good_1on1"]}, {"id": "sr_pip_scare", "character": "Calendar", "scenario": "Calendar invite from HR: **'Quick Chat.'** Friday 4:30 PM. No agenda. No description. No context. This is either about PTO policy or your career is over. No in between.", "leftOption": {"label": "Panic-apply to 12 companies", "effects": {"sanity": -7, "stability": -3}, "hiddenConsequences": [{"effects": {"sanity": 8, "stability": 5}, "description": "It was about the new PTO policy. False alarm. But you already have 3 onsites scheduled. Accidentally played yourself into a TC bump.", "delay": 1}], "roast": "Panic-applying to 12 companies over a rumor. Your LinkedIn is now a crime scene of desperation."}, "rightOption": {"label": "Dissociate until Friday", "effects": {"sanity": 3, "reputation": -2}, "hiddenConsequences": [{"effects": {"sanity": 5}, "description": "PTO policy update. You lost 4 days of productivity to raw existential dread. WLB is cope when HR has calendar access.", "delay": 1}], "roast": "Dissociating through a PIP scare. That's not WLB, that's a coping mechanism."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "sr_college_friend", "character": "Text Message", "scenario": "College friend is in town for one night. Haven't seen them in 2 years. But you have a deadline tomorrow and your **manager tracks commit timestamps**. Golden handcuffs vs. human connection.", "leftOption": {"label": "Skip it, grind (the TC demands it)", "effects": {"sanity": -4, "stability": 5}, "hiddenConsequences": null, "roast": "Skipping friends for the grind. Your TC can't sit with you at brunch."}, "rightOption": {"label": "Go out (WLB is not cope tonight)", "effects": {"sanity": 8, "stability": -3}, "hiddenConsequences": null, "roast": "Going out on a weeknight. Tomorrow's standup is going to be rough but at least you have friends."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "sr_prod_down_dinner", "character": "PagerDuty", "scenario": "**11 PM.** Dinner with your partner. Production is down. Phone won't stop buzzing. Your partner is staring at you. The RSUs are staring back.", "leftOption": {"label": "\"I'm at dinner\" (choose WLB)", "effects": {"sanity": -2, "reputation": -8, "stability": 3, "tc": 3}, "hiddenConsequences": null, "roast": "Choosing dinner over prod. Bold move for someone who just got paged in front of their date."}, "rightOption": {"label": "Open laptop at the restaurant (choose TC)", "effects": {"sanity": -4, "reputation": 8, "tc": -3}, "hiddenConsequences": null, "roast": "Opening your laptop at a restaurant. Your partner is already composing a Blind post about you."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "sr_no_pto", "character": "HR System", "scenario": "**No PTO in 8 months.** HR sends a 'friendly reminder' about use-it-or-lose-it. You can't take PTO because your team is **3 engineers doing 8 people's jobs**. Classic.", "leftOption": {"label": "Book a week off (radical act)", "effects": {"sanity": 8, "stability": -3, "tc": 2}, "hiddenConsequences": null, "roast": "Actually using PTO. Revolutionary. Your team will survive without you. Probably."}, "rightOption": {"label": "\"I'll take it later\" (cope)", "effects": {"sanity": -4, "stability": 5}, "hiddenConsequences": null, "roast": "'I'll take it later' \u2014 you have 47 days accrued and zero plans to use them."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "staff_directors", "character": "Director A", "scenario": "Two directors **beefing over platform strategy**. Both want you to publicly back them. Classic political crossfire. Pick wrong and your org gets dissolved in the next reorg.", "leftOption": {"label": "Back Director A", "effects": {"reputation": 8, "stability": -5}, "hiddenConsequences": [{"effects": {"reputation": -8}, "description": "Director B remembers everything. They just became your skip-level in the reorg. You're URA now. Unregretted attrition.", "delay": 5}], "roast": "Backing Director A. Hope you picked the winner, because the loser remembers everything."}, "rightOption": {"label": "Back Director B", "effects": {"reputation": -5, "stability": -5, "sanity": 3}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Director A lost. Your team got absorbed. Your new org has a 'culture of accountability.' That means PIPs.", "delay": 5}], "roast": "Backing Director B. Corporate Game of Thrones and you just chose a side. Good luck."}, "minStage": "staff", "maxStage": null, "isTutorial": false}, {"id": "staff_golden_handcuffs", "character": "Calculator App", "scenario": "You do the math. Leaving now means **forfeiting $400K in unvested RSUs**. 18 months left. Your soul has a price and it's exactly $400K. Is this peanuts?", "leftOption": {"label": "Stay for the bag (golden handcuffs)", "effects": {"tc": 8, "sanity": -7, "reputation": 2}, "hiddenConsequences": null, "roast": "Staying for the bag while your soul leaves your body. The handcuffs are working as designed."}, "rightOption": {"label": "Walk away (impossible choice)", "effects": {"tc": -8, "sanity": 8, "stability": -8, "reputation": 0}, "hiddenConsequences": null, "roast": "Walking away from unvested RSUs. Either brave or financially illiterate. Time will tell."}, "minStage": "staff", "maxStage": null, "isTutorial": false}, {"id": "staff_skip_level", "character": "VP", "scenario": "Skip-level wants to '**get your perspective on the team.**' Translation: they want dirt on your manager. It's a trap. Every answer is wrong.", "leftOption": {"label": "Corporate non-answers only", "effects": {"reputation": -2}, "hiddenConsequences": null, "roast": "Corporate non-answers to a skip-level. You just said nothing in 30 minutes. Promotion material."}, "rightOption": {"label": "Be honest (career suicide)", "effects": {"reputation": 8, "stability": -3, "sanity": 2}, "hiddenConsequences": [{"effects": {"stability": -8}, "description": "Your skip-level forwarded your 'candid feedback' to your manager. Verbatim. With your name attached. You played yourself.", "delay": 3}], "roast": "Being honest in a skip-level. RIP your next perf review."}, "minStage": "staff", "maxStage": null, "isTutorial": false}, {"id": "staff_strategy_doc", "character": "Google Docs", "scenario": "You wrote a **20-page strategy doc**. 14 people commented. **Nobody read past page 1.** The VP loved the title. 'Great thought leadership.' This is what Staff+ looks like.", "leftOption": {"label": "Schedule a review meeting (pain)", "effects": {"sanity": -4, "reputation": 5}, "hiddenConsequences": null, "roast": "Scheduling a meeting about a strategy doc. You just created work about work about work."}, "rightOption": {"label": "Let it die (accept the void)", "effects": {"sanity": -2, "reputation": -3}, "hiddenConsequences": null, "roast": "Letting the strategy doc die. One less artifact nobody would've read anyway."}, "minStage": "staff", "maxStage": null, "isTutorial": false}, {"id": "staff_partner_question", "character": "Partner", "scenario": "Your partner asks why you're still at a job that makes you miserable. You open the **RSU vesting calculator**. '**Just 18 more months.**' They've heard that before.", "leftOption": {"label": "\"Things will change\" (they won't)", "effects": {"sanity": -7, "tc": 3}, "hiddenConsequences": null, "roast": "'Things will change' \u2014 the most repeated lie in tech, right after 'we're like a family.'"}, "rightOption": {"label": "Show them the vesting schedule", "effects": {"sanity": -4, "tc": 5}, "hiddenConsequences": null, "roast": "Showing your partner the vesting schedule as relationship therapy. TC is not a love language."}, "minStage": "staff", "maxStage": null, "isTutorial": false}, {"id": "staff_mystery_meeting", "character": "Calendar", "scenario": "Invited to a meeting with **no agenda**. Everyone else seems to know what's happening. You're either about to get **promoted or managed out**. No way to tell.", "leftOption": {"label": "Ask questions (expose yourself)", "effects": {"reputation": -1, "sanity": -2}, "hiddenConsequences": null, "roast": "Asking questions in a mystery meeting. Now you're on the list AND they know you're paying attention."}, "rightOption": {"label": "Nod along (fake it energy)", "effects": {"reputation": 5, "stability": -3}, "hiddenConsequences": [{"effects": {"stability": -5, "sanity": -5}, "description": "You're now the DRI for decisions from that meeting. You still don't know what they were. But you're accountable. Good luck.", "delay": 4}], "roast": "Nodding along in a meeting you don't understand. Staff-level fake-it-till-you-make-it."}, "minStage": "staff", "maxStage": null, "isTutorial": false}, {"id": "principal_intern", "character": "Intern", "scenario": "An intern asks **what you do all day**. You start explaining. Halfway through, you realize you can't explain it either. 15 YOE and your job description is '**vibes and architecture.**'", "leftOption": {"label": "Pivot to mentoring them", "effects": {"sanity": -4, "reputation": 5}, "hiddenConsequences": null, "roast": "A Principal pivoting to mentor an intern. Your scope just went from 'org-wide impact' to 'explaining git rebase.'"}, "rightOption": {"label": "\"I make sure things don't break\"", "effects": {"sanity": -7, "reputation": 3}, "hiddenConsequences": null, "roast": "'I make sure things don't break' \u2014 Principal-level cope for 'I mass-approve PRs and attend meetings.'"}, "minStage": "staff", "maxStage": null, "isTutorial": false}, {"id": "principal_legacy", "character": "Slack DM", "scenario": "Someone pings you about a system you built 3 years ago. **Nobody else knows how it works.** Including you. The comments just say '**// don't touch this.**'", "leftOption": {"label": "Help debug (PTSD flashback)", "effects": {"sanity": -4, "stability": 5}, "hiddenConsequences": null, "roast": "Helping debug your own legacy code. The PTSD flashback is the real hidden consequence."}, "rightOption": {"label": "\"Deprecate it\" (rest and vest energy)", "effects": {"stability": -5, "sanity": 5}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "It can't be deprecated. It processes 40% of revenue. You built your own golden handcuffs. You are the legacy system.", "delay": 2}], "roast": "'Deprecate it' is Principal-speak for 'I refuse to look at my own mistakes from 2019.'"}, "minStage": "staff", "maxStage": null, "isTutorial": false}, {"id": "principal_monday", "character": "Mirror", "scenario": "Monday morning. You open your laptop. For a full minute, you **can't remember what you do here**. $500K TC to sit in meetings and say '**let's take this offline.**' Is this rest and vest?", "leftOption": {"label": "Check Slack (return to the matrix)", "effects": {"sanity": -7, "stability": 5, "tc": 4}, "hiddenConsequences": null, "roast": "Checking Slack on Monday. The matrix has you. It always had you."}, "rightOption": {"label": "Close laptop. Walk away.", "effects": {"sanity": 8, "stability": -5, "tc": -3}, "hiddenConsequences": null, "roast": "Closing the laptop and walking away. You'll be back in 20 minutes and we both know it."}, "minStage": "staff", "maxStage": null, "isTutorial": false}, {"id": "ai_copilot_pr", "character": "Tech Lead", "scenario": "**400-line PR.** Tech lead asks: 'Did you write this or did **Claude Code**?' Honestly? You don't know anymore. The vibes wrote the code. You just approved it.", "leftOption": {"label": "\"I wrote every line\" (lie)", "effects": {"reputation": 5, "sanity": -2}, "hiddenConsequences": [{"effects": {"reputation": -5}, "description": "Someone found the exact code on Stack Overflow. AI-generated. Verbatim. You're now known as the vibe coder. Mass.", "delay": 3}], "roast": "Claiming you wrote every line when Claude did the heavy lifting. Integrity has left the chat."}, "rightOption": {"label": "\"Claude Code wrote it\" (honest)", "effects": {"reputation": -3}, "hiddenConsequences": null, "roast": "Admitting Claude wrote it. Honest, but now your manager is Googling 'do we need this engineer.'"}, "minStage": "ramping", "maxStage": "senior", "isTutorial": false}, {"id": "ai_hackathon", "character": "VP of Engineering", "scenario": "Company-wide AI hackathon! 'Build something with LLMs in 48 hours!' Winner gets a **$50 gift card**. Your TC is $350K. The disrespect is palpable.", "leftOption": {"label": "Build a ChatGPT wrapper", "effects": {"sanity": -4, "reputation": 8, "tc": 3}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Your hackathon wrapper is now a 'strategic initiative.' You own it. No team. No budget. VP demoed it to the board. You're trapped.", "delay": 4}], "roast": "Building a ChatGPT wrapper at a hackathon. Groundbreaking innovation right there."}, "rightOption": {"label": "Skip it (protect your WLB)", "effects": {"reputation": -3, "sanity": 5, "tc": -3}, "hiddenConsequences": [{"effects": {"reputation": -5}, "description": "'Not showing AI-first mindset' in your quarterly feedback. That's a real thing now. Your refresher grant just got smaller.", "delay": 5}], "roast": "Skipping the hackathon for WLB. Based, but you just missed your one chance to build something fun."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false}, {"id": "ai_replace_team", "character": "CEO (All-Hands)", "scenario": "CEO: '**AI will let us do more with less.**' The 'less' is your team. Stock jumps 12%. Blind erupts. 'Trust me bro, **layoffs in 2 weeks.**'", "leftOption": {"label": "Start learning prompt engineering", "effects": {"sanity": -2, "stability": 1, "tc": 3}, "hiddenConsequences": null, "roast": "Learning prompt engineering to survive. You're one 'AI-native' buzzword away from a LinkedIn influencer arc."}, "rightOption": {"label": "Post the all-hands transcript to Blind", "effects": {"sanity": 8, "stability": -5, "tc": -3}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Your Blind post went viral. Someone replied: 'I know exactly who posted this.' They DMed your manager. You're cooked.", "delay": 3}], "roast": "Posting the all-hands transcript to Blind. Whistleblower or chaos agent? Yes."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "ai_pm_feature", "character": "Product Manager", "scenario": "PM: '**Can we add AI to the settings page?** Board wants to see AI everywhere.' You stare blankly. '**Like a sparkle icon or something?**' They're dead serious.", "leftOption": {"label": "\"That makes zero sense\"", "effects": {"reputation": -5, "sanity": -2, "tc": 3}, "hiddenConsequences": null, "roast": "Telling the PM their AI feature makes no sense. Correct, but enjoy your 'not a team player' feedback."}, "rightOption": {"label": "Add sparkle emoji, call it AI", "effects": {"reputation": 8, "sanity": -4}, "hiddenConsequences": [{"effects": {"reputation": 10}, "description": "CEO saw the sparkle in the demo. 'THIS is AI-first thinking.' Shoutout in all-hands. Your TC just went up for adding a Unicode character.", "delay": 3}], "roast": "Adding a sparkle emoji and calling it AI. You just shipped the most honest AI feature in the industry."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false}, {"id": "ai_intern_cursor", "character": "Summer Intern", "scenario": "The intern built your **entire Q3 roadmap in one afternoon** using Cursor. It works. Your 8 YOE suddenly feel mass. Your manager is very, very quiet.", "leftOption": {"label": "\"Let me review for production readiness\"", "effects": {"reputation": 5, "sanity": -4}, "hiddenConsequences": null, "roast": "Reviewing an intern's AI-generated code 'for production readiness.' It's all AI code. You're reviewing AI."}, "rightOption": {"label": "Quietly rewrite it (cope)", "effects": {"sanity": -2, "stability": 5}, "hiddenConsequences": [{"effects": {"reputation": -5}, "description": "Intern posted on HN: 'Senior engineer mass-rewrites my working code because ego.' Front page. 847 comments. You're cooked.", "delay": 5}], "roast": "Quietly rewriting the intern's code. Unpaid QA for a robot. This is your life now."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false}, {"id": "ai_prompt_eng", "character": "LinkedIn", "scenario": "A '**Prompt Engineer**' with 6 months experience just posted their **$350K offer**. You have 8 YOE and make less. They listed their TC on Blind. The comments are ruthless.", "leftOption": {"label": "Add 'AI/ML' to your LinkedIn", "effects": {"sanity": -2, "tc": 5}, "hiddenConsequences": null, "roast": "Adding 'AI/ML' to your LinkedIn. You and 4 million other people who watched one YouTube video."}, "rightOption": {"label": "Rage-close LinkedIn forever", "effects": {"sanity": -4, "tc": 3}, "hiddenConsequences": null, "roast": "Rage-closing LinkedIn forever. The only winning move in the AI hype game."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "ai_code_review", "character": "Coworker", "scenario": "Coworker submits a PR that's **100% AI slop**. Comments are hallucinated. Variable names don't match the codebase. Tests pass by pure coincidence. 'LGTM?'", "leftOption": {"label": "Leave honest review (get labeled)", "effects": {"sanity": -2, "reputation": -3, "stability": 3, "tc": 4}, "hiddenConsequences": [{"effects": {"reputation": -5}, "description": "You're now 'the person who doesn't embrace AI tools.' Manager scheduled a 'mindset alignment chat.' Mass behavior.", "delay": 4}], "roast": "Leaving an honest review on AI-generated code. Enjoy being 'that person who slows things down.'"}, "rightOption": {"label": "LGTM (not your circus)", "effects": {"sanity": -2, "stability": 2, "tc": -3}, "hiddenConsequences": [{"effects": {"stability": -8}, "description": "The hallucinated code hit prod. It was generating fake user data. Legal is involved. Your LGTM is evidence. Cooked.", "delay": 3}], "roast": "LGTM on code nobody wrote. You just approved a hallucination into production."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false}, {"id": "ai_layoff_automation", "character": "Slack #general", "scenario": "The '**AI Transformation**' team shipped an internal tool that does **60% of your team's work**. Manager says 'don't worry about it.' That's exactly what they said before the last round of layoffs.", "leftOption": {"label": "Pivot to 'AI oversight' role", "effects": {"reputation": 5, "stability": -3, "sanity": -2}, "hiddenConsequences": null, "roast": "Pivoting to 'AI oversight.' That's just a PIP with extra steps."}, "rightOption": {"label": "Double down on what you do", "effects": {"stability": -5}, "hiddenConsequences": [{"effects": {"stability": -8}, "description": "Team got 'consolidated.' You now report to the AI Transformation lead. They're 24 with 2 YOE. Your TC is higher than theirs. For now.", "delay": 5}], "roast": "Doubling down on your craft while AI eats your lunch. Romantic but the market doesn't care."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "ai_chatbot_demo", "character": "VP of Product", "scenario": "VP wants an AI chatbot demo for the board in 2 weeks. '**Just use the OpenAI API. How hard can it be?**' Famous last words from someone who's never deployed anything.", "leftOption": {"label": "Build it properly (RIP your life)", "effects": {"sanity": -7, "reputation": 8}, "hiddenConsequences": [{"effects": {"sanity": -5}, "description": "Chatbot told a board member their product was 'mediocre at best.' It wasn't wrong. You're still in trouble. AI has zero chill.", "delay": 2}], "roast": "Building the chatbot properly. Your demo is in 3 days and you're setting up Kubernetes. Rest in peace."}, "rightOption": {"label": "Hardcode the demo (big brain)", "effects": {"sanity": -2, "reputation": -3, "stability": 3}, "hiddenConsequences": [{"effects": {"stability": -8}, "description": "Board loved it. Now it's a Q1 priority. 2 engineers. 6-week deadline. The hardcoded version is the 'MVP.' You played yourself.", "delay": 4}], "roast": "Hardcoding the demo. If the CEO clicks anything not on the script, you're cooked."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "ai_slop_docs", "character": "Technical Writer", "scenario": "All documentation is now **AI-generated**. It's confident, articulate, and **completely wrong**. Users are filing bugs based on features that don't exist. The AI wrote about them with such conviction.", "leftOption": {"label": "Fix the docs yourself (unpaid labor)", "effects": {"sanity": -4, "reputation": 5}, "hiddenConsequences": null, "roast": "Fixing AI-generated docs yourself. Volunteering for unpaid janitorial work on a robot's output."}, "rightOption": {"label": "Let it ride (not my problem)", "effects": {"stability": -3}, "hiddenConsequences": [{"effects": {"stability": -5, "reputation": -3}, "description": "Sales demo failed because they quoted AI docs about features that don't exist. Your name was on the spec. You're in the blast radius.", "delay": 4}], "roast": "Letting AI slop docs ride. Future you will spend 3 hours debugging because of a hallucinated API."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false}, {"id": "ai_standup_bot", "character": "Engineering Manager", "scenario": "Manager replaced standup with an **AI bot** that summarizes PRs. Bot says you've **done nothing this sprint**. You merged 12 PRs. The bot is lying. Your manager believes the bot.", "leftOption": {"label": "Correct the bot publicly", "effects": {"reputation": -3, "sanity": 5}, "hiddenConsequences": null, "roast": "Correcting the bot publicly. Now everyone knows you actually track what you do. Suspicious."}, "rightOption": {"label": "Let manager believe the bot (suicidal)", "effects": {"sanity": -4, "stability": -3, "reputation": 3}, "hiddenConsequences": [{"effects": {"reputation": -5, "tc": -3}, "description": "Perf review cited 'low output.' Evidence: the AI bot. You got downleveled. A robot tanked your TC. We live in a simulation.", "delay": 5}], "roast": "Letting your manager believe the bot's summary. Living dangerously with AI as your spokesperson."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false}, {"id": "ai_vibe_coding", "character": "Blind", "scenario": "Blind hot take: 'If you're not **vibe coding** in 2025, you're mass already. Writing code manually is mass. LC grinding is mass. **Just vibe bro.**' 4,000 upvotes. The world is broken.", "leftOption": {"label": "Embrace the vibes (surrender)", "effects": {"sanity": -2, "tc": 5}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Your vibe-coded microservice has 47 dependencies, 0 tests, and handles payroll. It's in production. Godspeed.", "delay": 3}], "roast": "Embracing vibe coding. You've stopped fighting the future and started vibing with the void."}, "rightOption": {"label": "Keep typing code like a boomer", "effects": {"sanity": 5, "reputation": -3}, "hiddenConsequences": null, "roast": "Typing code manually like a boomer. Respect the craft, even if the craft doesn't respect your timeline."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "ai_chief_ai_officer", "character": "CEO (Email)", "scenario": "Company hired a '**Chief AI Officer.**' LinkedIn: 'AI Visionary | Thought Leader | Ex-McKinsey | **0 YOE in engineering.**' They want to 'audit your codebase for AI opportunities.'", "leftOption": {"label": "Cooperate fully (dead inside)", "effects": {"sanity": -4, "stability": 5}, "hiddenConsequences": [{"effects": {"sanity": -5, "stability": -3}, "description": "The 'audit' is a 90-slide deck recommending you replace your backend with 'an agentic AI mesh.' Budget: $2M. Timeline: 6 weeks. Their TC is higher than yours.", "delay": 4}], "roast": "Cooperating with the Chief AI Officer. You're now helping someone with no technical background make technical decisions."}, "rightOption": {"label": "Passive-aggressively comply", "effects": {"sanity": -2, "reputation": -3}, "hiddenConsequences": null, "roast": "Passive-aggressively complying with the CAIO. Malicious compliance is an art form and you're Picasso."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "principal_board", "character": "Board of Directors", "scenario": "Board wants a 'deep dive' on your org's OKRs. You have **2 hours to justify your team's existence**. Your entire career comes down to 12 slides and 3 metrics you don't control.", "leftOption": {"label": "Prepare obsessively (sell your weekend)", "effects": {"sanity": -8, "reputation": 8, "tc": -1}, "hiddenConsequences": null, "roast": "Preparing obsessively for a board presentation. Your weekend died so a VP could take credit."}, "rightOption": {"label": "Wing it with Staff energy", "effects": {"reputation": -5}, "hiddenConsequences": [{"effects": {"stability": -8}, "description": "Board was not impressed. Your org is 'under review.' That's corporate for 'start updating your Blind profile.'", "delay": 2}], "roast": "Winging a board presentation with Staff energy. Either genius or unemployment. No in-between."}, "minStage": "staff", "maxStage": null, "isTutorial": false}, {"id": "blind_rto_mandate", "character": "CEO (All-Hands)", "scenario": "CEO announces RTO: **3 days in office minimum**. 'Culture happens in person.' Blind explodes. '**RTO = Return To Oppression.**' Your 2-hour commute just became your personality.", "leftOption": {"label": "Comply like a good drone", "effects": {"sanity": -4, "stability": 8}, "hiddenConsequences": null, "roast": "Complying with RTO like a drone. Your 2-hour commute just became your personality."}, "rightOption": {"label": "Quietly ignore it (WFH rebel)", "effects": {"sanity": 5, "stability": -5}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Badge swipe data says you've been in office 4 times in 3 months. HR sent a 'compliance reminder.' First warning before PIP.", "delay": 4}], "roast": "Quietly ignoring RTO. Bold move for someone whose badge swipes are being tracked."}, "minStage": "contributing", "maxStage": null, "isTutorial": false, "excludes": ["amazon_rto_mandate"]}, {"id": "blind_lc_grind", "character": "LeetCode", "scenario": "You're grinding LC **during work hours**. Manager walks by. Screen shows '**Two Sum**' in Python. You're a senior backend engineer. At a FAANG. Using Java. This looks bad.", "leftOption": {"label": "Alt-tab to Jira (panic)", "effects": {"sanity": -2, "stability": -3}, "hiddenConsequences": null, "roast": "Alt-tabbing to Jira when caught doing LeetCode. Nobody buys it. JIRA hasn't been updated in 3 sprints."}, "rightOption": {"label": "\"Just brushing up on fundamentals\"", "effects": {"reputation": -3, "sanity": -2, "tc": 3}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Manager told your skip-level you're interviewing. You're now on the flight risk list. Your refresher grant: $0. They're managing you out.", "delay": 3}], "roast": "'Brushing up on fundamentals' at work. Your manager just added 'flight risk' to their notes."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false}, {"id": "blind_oe_caught", "character": "HR", "scenario": "You've been **OE for 6 months**. Two jobs. Two laptops. **$600K combined TC.** Life is good. Then your J2 manager schedules a meeting at the same time as your J1 standup.", "leftOption": {"label": "Skip J2 standup (risky)", "effects": {"tc": 5, "stability": -5}, "hiddenConsequences": [{"effects": {"tc": -8, "stability": -5}, "description": "J2 flagged you for low engagement. They ran a background check. Found J1. Fired from both. TC went from $600K to $0. OE speedrun.", "delay": 4}], "roast": "Skipping J2 standup. If a tree falls in a forest and no one is on the Zoom, did the standup happen?"}, "rightOption": {"label": "Clone yourself across two Zooms", "effects": {"sanity": -4, "tc": 8}, "hiddenConsequences": [{"effects": {"sanity": -8}, "description": "You accidentally screenshared J1's Slack in J2's standup. Your manager at J2 saw your J1 manager's name. The jig is up.", "delay": 3}], "roast": "Two Zooms at once. You're not overemployed, you're under-cammed."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false}, {"id": "blind_rest_vest", "character": "Blind", "scenario": "You haven't shipped anything in **3 months**. Your RSUs vest quarterly. You attend meetings, say '**let's align offline**,' and collect $450K/yr. Is this rest and vest or are you just... done?", "leftOption": {"label": "Lean into it (rest and vest master)", "effects": {"sanity": 5, "tc": 5, "reputation": -5}, "hiddenConsequences": [{"effects": {"stability": -8}, "description": "Stack ranking caught up. You're in the bottom 10%. PIP incoming. Rest and vest has a shelf life. Yours just expired.", "delay": 5}], "roast": "Fully committing to rest and vest. Your PRs per quarter are now a rounding error."}, "rightOption": {"label": "Actually try again (cringe)", "effects": {"sanity": -4, "reputation": 8}, "hiddenConsequences": null, "roast": "Actually trying again after rest-and-vesting. The team doesn't even know what you do anymore."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "blind_dating_tc", "character": "Hinge", "scenario": "Matched with someone on Hinge. Third message: 'So what do you do?' You say SWE. '**Oh nice, what's your TC?**' They're also in tech. In SF, **TC is foreplay.**", "leftOption": {"label": "Share your TC (flex)", "effects": {"sanity": -2, "reputation": 5, "tc": 3}, "hiddenConsequences": [{"effects": {"sanity": -5}, "description": "They unmatched. Your TC wasn't high enough. They were L6 at Meta. Your peanuts couldn't compete. Back to LC grinding.", "delay": 2}], "roast": "Sharing your TC on a date. Nothing says romance like 'my RSUs vest quarterly.'"}, "rightOption": {"label": "\"I don't share that\" (sus)", "effects": {"reputation": -3, "tc": -3}, "hiddenConsequences": [{"effects": {"sanity": -3}, "description": "They assumed your TC is low. Unmatched. Posted on Blind: 'Went on a date with someone who won't share TC. Red flag or peanuts?' 500 upvotes.", "delay": 2}], "roast": "Refusing to share TC on a date. Now they think you're either broke or in stealth wealth cope."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "blind_glassdoor_revenge", "character": "Glassdoor", "scenario": "You just got **PIP'd**. The rage is nuclear. Glassdoor is open. Your keyboard is ready. Time to **burn it all down** with a 1-star review that names names.", "leftOption": {"label": "Write the scorched-earth review", "effects": {"sanity": 8, "stability": -5, "tc": 2}, "hiddenConsequences": [{"effects": {"reputation": -5}, "description": "HR traced the review. Too many specific details. You're now blacklisted from the company and their 4 sister orgs. URA with prejudice.", "delay": 3}], "roast": "Scorched-earth Glassdoor review. Cathartic, but now HR is cross-referencing writing styles."}, "rightOption": {"label": "Take the high road (cope)", "effects": {"sanity": -1, "stability": -5}, "hiddenConsequences": null, "roast": "Taking the high road on Glassdoor. Your restraint is admirable and completely wasted."}, "minStage": "contributing", "maxStage": null, "isTutorial": false, "excludes": ["boost_good_review", "boost_spot_bonus", "life_good_1on1"]}, {"id": "blind_linkedin_excited", "character": "LinkedIn", "scenario": "You just joined a new company. Your recruiter DMs: 'Don't forget to post the **excited-to-announce!**' You stare at the draft. 'Excited to announce...' The cringe is physical.", "leftOption": {"label": "Post the cringe (play the game)", "effects": {"reputation": 8, "sanity": -4}, "hiddenConsequences": [{"effects": {"sanity": -3}, "description": "847 likes from people you've never met. 12 'Congrats!' comments from recruiters. Your Blind alt posted 'LinkedIn is so mass.' The duality of SWE.", "delay": 2}], "roast": "Posting 'I'm excited to announce' on LinkedIn. Your soul just left your body mid-sentence."}, "rightOption": {"label": "Refuse (maintain dignity)", "effects": {"reputation": -3, "sanity": 5}, "hiddenConsequences": null, "roast": "Refusing to post on LinkedIn. Maintaining dignity in silence. Nobody will know you exist."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "blind_pip", "character": "Manager", "scenario": "Stack ranking season. Your manager says you're '**not meeting the bar.**' You shipped 3 features this quarter. The person next to you shipped 0 and **got promoted**. Welcome to PIP culture.", "leftOption": {"label": "Fight the PIP (lawyer up)", "effects": {"sanity": -7, "stability": -3}, "hiddenConsequences": [{"effects": {"stability": 8, "reputation": 5}, "description": "You survived the PIP. Barely. Your manager got moved to a different org. Pyrrhic victory. Your soul is gone but the RSUs vest next month.", "delay": 4}], "roast": "Fighting the PIP with a lawyer. You're about to spend your sign-on bonus on legal fees."}, "rightOption": {"label": "Take the package and bounce", "effects": {"tc": -5, "sanity": 8, "stability": -5}, "hiddenConsequences": null, "roast": "Taking the package and bouncing. URA secured. Enjoy your garden leave arc."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false, "excludes": ["boost_good_review", "boost_spot_bonus", "life_good_1on1"]}, {"id": "blind_refresher_grant", "character": "E*Trade", "scenario": "Refresher grant just hit. You were expecting $200K over 4 years. You got **$40K**. That's $10K/year. Pre-tax. Your manager calls it '**competitive.**' Blind calls it peanuts. They're right.", "leftOption": {"label": "Smile and say thanks (dead inside)", "effects": {"sanity": -4, "tc": -3, "reputation": 3}, "hiddenConsequences": null, "roast": "Smiling and saying thanks for peanuts. Your refresher wouldn't cover a month of Bay Area rent."}, "rightOption": {"label": "Demand more (TC or GTFO)", "effects": {"reputation": -5, "tc": 5}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Manager said 'this is what the band allows.' You posted the refresher amount on Blind. 'Is $10K/yr refresher peanuts?' 1200 replies. All saying yes.", "delay": 3}], "roast": "Demanding more TC. Bold strategy. Your manager just flagged you as 'difficult to retain' which, ironically, might work."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "blind_tc_comparison", "character": "Blind", "scenario": "Blind post: '5 YOE, $280K TC, L5 at a FAANG. **Is this peanuts?**' You have 8 YOE and make $220K. You close the app. Open it again. Close it. Open it. The cycle continues.", "leftOption": {"label": "Reply \"that's peanuts bro\"", "effects": {"sanity": -4, "reputation": 3}, "hiddenConsequences": null, "roast": "Calling someone's TC 'peanuts' on Blind. Congrats, you're now the main character for 24 hours."}, "rightOption": {"label": "Start the LC grind tonight", "effects": {"sanity": -4, "tc": 5}, "hiddenConsequences": [{"effects": {"sanity": -5}, "description": "3 months of LC grinding. 200 problems solved. Got a Meta offer. TC jumped 40%. Was it worth the mental breakdown? Blind says yes. Your therapist says no.", "delay": 5}], "roast": "Starting the LC grind because someone on Blind out-earns you. Comparison is the thief of rest-and-vest."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "amazon_pip_culture", "character": "Amazon Manager", "scenario": "Stack ranking season. Your manager explains URA targets: '**We need to PIP 10% of the team.** It's not personal \u2014 it's the Leadership Principles.' You have 14 LPs memorized. It wasn't enough.", "leftOption": {"label": "Pivot to AWS (lateral escape)", "effects": {"stability": -5, "sanity": 1}, "hiddenConsequences": null, "roast": "Pivoting to AWS to escape a PIP. Lateral moves are just PIPs with better branding."}, "rightOption": {"label": "Write a 6-pager defending yourself", "effects": {"sanity": -4, "reputation": 5}, "hiddenConsequences": [{"effects": {"stability": -8}, "description": "Your 6-pager was forwarded to HR. They used it as evidence for the PIP. 'Demonstrates lack of ownership.' You literally quoted the Ownership LP. Kafkaesque.", "delay": 3}], "roast": "Writing a 6-pager to defend yourself. You're using Amazon's own bureaucracy against it. Respect."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false, "excludes": ["boost_good_review", "boost_spot_bonus", "life_good_1on1"]}, {"id": "amazon_oncall_hell", "character": "PagerDuty", "scenario": "Week 3 of on-call. A **Sev-2 fires at 3 AM** \u2014 a customer in EU can't check out. Your COE from last week's incident isn't even finished. '**Customer Obsession**' means you don't sleep.", "leftOption": {"label": "Acknowledge and go back to sleep", "effects": {"sanity": 5, "stability": -5}, "hiddenConsequences": null, "roast": "Acknowledging the page and going back to sleep. Your SLA just became a suggestion."}, "rightOption": {"label": "Roll out of bed and fix it", "effects": {"sanity": -4, "reputation": 5}, "hiddenConsequences": null, "roast": "Rolling out of bed at 3 AM for a severity-2. The oncall rotation owns you."}, "minStage": "ramping", "maxStage": "senior", "isTutorial": false}, {"id": "google_perf", "character": "Google TL", "scenario": "Perf season at Google. Your TL says you need '**more impact**' for L5 promo. You redesigned a system serving 2B queries/day. '**But did you write a Dapper paper about it?**' Peer reviews are due Friday.", "leftOption": {"label": "Stay at L4 forever (rest and vest)", "effects": {"tc": 5, "sanity": 5, "reputation": -3}, "hiddenConsequences": null, "roast": "L4 forever, rest and vest. You've achieved the Google dream: doing nothing at scale."}, "rightOption": {"label": "Launch a new project for promo fodder", "effects": {"sanity": -4, "reputation": 8}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Your promo project launched, got 50 users, and was deprecated. But the promo committee liked the design doc. You're now L5. The project is dead. This is how it works.", "delay": 4}], "roast": "Launching a new project for promo. 90% of Google promo projects get abandoned post-promotion."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false}, {"id": "google_food", "character": "Google Cafeteria", "scenario": "Google cut the **free dinner benefit**. Now food is only served until 6 PM. The Blind post '**Google is dead**' has 847 upvotes. Someone called it 'the beginning of the end.' It's a free lunch. At a $1.7T company.", "leftOption": {"label": "Post a rant on Blind", "effects": {"sanity": 5, "reputation": -3}, "hiddenConsequences": null, "roast": "Ranting on Blind about Google food quality. First-world problems have a new poster child."}, "rightOption": {"label": "Eat the free lunch in silence", "effects": {"sanity": -2}, "hiddenConsequences": null, "roast": "Eating the free lunch in silence. You're complaining about free food while making $500K. Read the room."}, "minStage": "newHire", "maxStage": null, "isTutorial": false}, {"id": "meta_zuck_pivot", "character": "Mark Zuckerberg", "scenario": "All-hands. Zuck announces the company is **pivoting. Again.** Last year: metaverse. This year: AI. Your entire team's roadmap is now irrelevant. '**Move fast and break things**' \u2014 including your career.", "leftOption": {"label": "Quietly update your LinkedIn", "effects": {"stability": -3, "sanity": 5}, "hiddenConsequences": null, "roast": "Updating your LinkedIn during a pivot. 'Open to opportunities' is the modern white flag."}, "rightOption": {"label": "Pivot your team to AI overnight", "effects": {"sanity": -4, "reputation": 8}, "hiddenConsequences": [{"effects": {"reputation": -8}, "description": "Your 'AI pivot' was rebranding a CRUD app with 'Powered by AI' in the footer. Leadership loved the deck. Eng Twitter found out. You're a meme now.", "delay": 3}], "roast": "Pivoting your team to AI overnight. Yesterday it was metaverse. Your roadmap has whiplash."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "meta_perf_rating", "character": "Meta Manager", "scenario": "PSC results are in. You got '**Met Most Expectations.**' Your manager says that's good. Blind says it's a **soft PIP**. Your refresher grant says $0. The Kool-Aid tastes different now.", "leftOption": {"label": "Start interviewing immediately", "effects": {"stability": -5, "tc": 5}, "hiddenConsequences": null, "roast": "Interviewing after a bad rating. Your Blind throwaway account is working overtime."}, "rightOption": {"label": "Grind harder next half", "effects": {"sanity": -4, "reputation": 5}, "hiddenConsequences": null, "roast": "Grinding harder after a bad rating. The definition of insanity is doing the same thing and expecting a different promo."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false, "excludes": ["boost_good_review", "boost_spot_bonus", "life_good_1on1"]}, {"id": "apple_secrecy", "character": "Apple Security", "scenario": "You mentioned your project name in a text to your partner. **Security pulls you into a room.** 'We take information security very seriously.' Your badge is confiscated during the investigation. You still don't know if you're fired.", "leftOption": {"label": "Lawyer up", "effects": {"stability": -5, "tc": -5, "reputation": 3}, "hiddenConsequences": [{"effects": {"stability": 8}, "description": "Legal confirmed you didn't violate NDA. You get your badge back. Security guy doesn't make eye contact anymore. You now communicate exclusively in code names.", "delay": 2}], "roast": "Lawyering up against Apple Legal. Bringing a knife to a thermonuclear war."}, "rightOption": {"label": "Apologize profusely and comply", "effects": {"sanity": -1, "stability": -5}, "hiddenConsequences": null, "roast": "Apologizing to Apple Legal. You just signed away rights you didn't know you had."}, "minStage": "ramping", "maxStage": null, "isTutorial": false}, {"id": "apple_rto_bus", "character": "Apple HR", "scenario": "Apple Park requires **3 days in-office minimum**. Your commute is **2 hours each way**. The shuttle has no WiFi. Tim Cook says in-person collaboration is 'irreplaceable.' Your Blind post about this got mass upvotes.", "leftOption": {"label": "Move closer (goodbye savings)", "effects": {"tc": -5, "stability": 5}, "hiddenConsequences": null, "roast": "Moving closer to Cupertino. Say goodbye to your savings and hello to a studio apartment."}, "rightOption": {"label": "Commute and suffer", "effects": {"sanity": -4}, "hiddenConsequences": null, "roast": "Commuting 2 hours each way for Apple. Your car is now your primary residence."}, "minStage": "newHire", "maxStage": null, "isTutorial": false}, {"id": "netflix_keeper_test", "character": "Netflix Director", "scenario": "Your director asks: '**Would I fight to keep you** if you said you were leaving?' This is the **Keeper Test**. There's no right answer. If they hesitate, you're already gone. Generous severance though.", "leftOption": {"label": "\"Would YOU pass the Keeper Test?\"", "effects": {"reputation": -5, "sanity": 8}, "hiddenConsequences": [{"effects": {"stability": -8}, "description": "Your director did not appreciate the reverse Keeper Test. You've been 'counseled out' with 4 months severance. Somehow this is considered a win on Blind.", "delay": 2}], "roast": "Asking your manager if THEY'D pass the Keeper Test. Sigma energy, zero self-preservation."}, "rightOption": {"label": "Smile and say you love it here", "effects": {"sanity": -2, "stability": 5}, "hiddenConsequences": null, "roast": "Saying you love it at Netflix. The Keeper Test is just a PIP with better PR."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "netflix_no_wlb", "character": "Netflix Slack", "scenario": "Netflix has '**unlimited PTO.**' You've taken 3 days this year. Your manager takes none. The culture doc says '**we're a team, not a family.**' The severance package says 'we meant it.'", "leftOption": {"label": "Book 2 weeks off (assert dominance)", "effects": {"sanity": 8, "stability": -5}, "hiddenConsequences": null, "roast": "Taking 2 weeks off at Netflix. Unprecedented. Your Slack will have 4,000 unreads when you return."}, "rightOption": {"label": "Take a long weekend (compromise)", "effects": {"sanity": 5, "reputation": -3}, "hiddenConsequences": null, "roast": "A long weekend at Netflix is basically a sabbatical. The bar is underground."}, "minStage": "ramping", "maxStage": null, "isTutorial": false}, {"id": "boost_offsite", "character": "Team Lead", "scenario": "Team offsite in Napa! Two days of 'team bonding' that's really just **drinking on the company card**. Your manager is doing karaoke. The VP is crying about their divorce. Best day at this company.", "leftOption": {"label": "Go all in (wine + vibes)", "effects": {"sanity": 8, "reputation": -3}, "hiddenConsequences": null, "roast": "Going all in at the offsite. Tomorrow's hangover is future you's problem."}, "rightOption": {"label": "Network strategically (grind never stops)", "effects": {"reputation": 8, "stability": 3, "sanity": -2}, "hiddenConsequences": null, "roast": "Networking strategically at an offsite. The grind never sleeps, even with an open bar."}, "minStage": "ramping", "maxStage": "senior", "isTutorial": false}, {"id": "boost_good_review", "character": "Manager", "scenario": "Perf review just dropped. '**Exceeds Expectations.**' Your manager actually wrote specific examples. Named real projects. Someone at this company sees you. This feeling won't last.", "leftOption": {"label": "Celebrate (you earned it)", "effects": {"sanity": 8, "reputation": -3}, "hiddenConsequences": null, "roast": "Celebrating a good review. Enjoy it for exactly 30 seconds before the imposter syndrome kicks in."}, "rightOption": {"label": "Ask about the promo timeline", "effects": {"tc": 5, "reputation": 3, "stability": -3}, "hiddenConsequences": null, "roast": "Immediately asking about promo after a good review. You speedran gratitude in record time."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false}, {"id": "boost_ship_day", "character": "Slack #releases", "scenario": "Your feature shipped. **Real users are using it.** Someone posted a screenshot saying '**this is exactly what I needed.**' 4 months of work, one moment of pure validation. Screenshot saved.", "leftOption": {"label": "Share in #wins (brag doc material)", "effects": {"sanity": 5, "reputation": 8, "stability": -3}, "hiddenConsequences": null, "roast": "Posting in #wins. Your brag doc is writing itself. TC-maximizing behavior."}, "rightOption": {"label": "Quietly smile and start the next ticket", "effects": {"sanity": 8, "reputation": -3}, "hiddenConsequences": null, "roast": "Quietly smiling and moving on. Humble, but your manager literally cannot promote what they don't see."}, "minStage": "ramping", "maxStage": "contributing", "isTutorial": false}, {"id": "boost_free_lunch", "character": "Office Kitchen", "scenario": "Catered lunch today. Not the usual sad sandwiches \u2014 **actual good food**. Sushi, poke bowls, the works. Someone in facilities went rogue. **Morale is temporarily restored.**", "leftOption": {"label": "Eat three plates (no shame)", "effects": {"sanity": 5, "stability": -3}, "hiddenConsequences": null, "roast": "Three plates at the free lunch. Your TC-per-calorie ratio is immaculate."}, "rightOption": {"label": "Take some home for dinner (WLB win)", "effects": {"sanity": 3, "tc": 3, "stability": -3}, "hiddenConsequences": null, "roast": "Taking leftovers home. WLB win and meal prep? You've optimized the corporate game."}, "minStage": "newHire", "maxStage": "contributing", "isTutorial": false}, {"id": "boost_wfh_friday", "character": "Slack", "scenario": "Manager posts: '**No meetings Friday.** Work from wherever.' The entire team goes silent on Slack by 2 PM. Nobody questions it. This is **peak WLB** and everyone knows it.", "leftOption": {"label": "Actually work from home", "effects": {"sanity": 5, "stability": 3, "reputation": -3}, "hiddenConsequences": null, "roast": "Actually working from home on WFH Friday. You and 3 other people in the company."}, "rightOption": {"label": "Work from a coffee shop (main character arc)", "effects": {"sanity": 8, "stability": -3}, "hiddenConsequences": null, "roast": "Working from a coffee shop. Main character energy with a $7 oat latte."}, "minStage": "newHire", "maxStage": "ramping", "isTutorial": false}, {"id": "boost_spot_bonus", "character": "E*Trade", "scenario": "**Surprise bonus: $5K.** Manager says 'thanks for going above and beyond on the incident.' You were going to do it anyway for the RSUs but hey, free money is free money.", "leftOption": {"label": "Thank your manager publicly", "effects": {"tc": 5, "reputation": 3, "stability": -3}, "hiddenConsequences": null, "roast": "Thanking your manager publicly for a spot bonus. That's $500 pre-tax. Don't spend it all in one place."}, "rightOption": {"label": "Quietly pocket it (don't make it weird)", "effects": {"tc": 5, "sanity": 3, "reputation": -3}, "hiddenConsequences": null, "roast": "Quietly pocketing a spot bonus. The IRS will find out even if your team doesn't."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false}, {"id": "boost_mentor_moment", "character": "Junior Engineer", "scenario": "A junior engineer you mentored just got promoted. They **thanked you in their promo doc** by name. Your manager noticed. For once, helping someone paid off. Literally.", "leftOption": {"label": "Add it to your own brag doc", "effects": {"reputation": -3, "sanity": 3}, "hiddenConsequences": null, "roast": "Adding a mentoring moment to your brag doc. Weaponizing kindness for promo. Efficient."}, "rightOption": {"label": "Just feel good about it (rare W)", "effects": {"sanity": 8, "reputation": -3}, "hiddenConsequences": null, "roast": "Feeling good without documenting it. That's not a W, that's a missed promo data point."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "boost_stock_pop", "character": "CNBC Alert", "scenario": "Your company stock just **popped 15%** on earnings. Your unvested RSUs are looking juicy. Blind is euphoric. '**Diamond hands vindicated.**' The golden handcuffs feel warm today.", "leftOption": {"label": "Check your vesting schedule (dopamine hit)", "effects": {"tc": 8, "sanity": 5, "reputation": -3}, "hiddenConsequences": null, "roast": "Checking your vesting schedule after a stock pop. The dopamine hit is better than any promo."}, "rightOption": {"label": "Sell the vested shares immediately", "effects": {"tc": 5, "stability": 3, "sanity": -2}, "hiddenConsequences": null, "roast": "Selling vested shares immediately. Locking in gains like a rational adult. Boring but smart."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "life_teammate_burnout", "character": "Work Bestie", "scenario": "Your closest teammate just went on **indefinite medical leave**. Burnout. The Slack message said 'taking time to focus on my health.' Everyone knows what that means. Their Jira tickets are now yours.", "leftOption": {"label": "Absorb their work (RIP your sanity)", "effects": {"sanity": -4, "stability": 5, "reputation": 3}, "hiddenConsequences": [{"effects": {"sanity": -5}, "description": "You're now doing two people's jobs for one person's TC. The burnout that took your teammate is whispering your name. You feel it in the 3 AM commits.", "delay": 4}], "roast": "Absorbing a burned-out teammate's work. Congratulations, now there are two burnouts."}, "rightOption": {"label": "Push back on scope (protect yourself)", "effects": {"sanity": -2, "reputation": -3}, "hiddenConsequences": null, "roast": "Pushing back on scope while your teammate drowns. Self-preservation is ugly but necessary."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "life_team_shrinks", "character": "Slack #general", "scenario": "Two more people left this quarter. **No backfills approved.** Manager says '**we're doing more with less.**' Translation: you're doing more with more burnout. The team Slack channel is a ghost town.", "leftOption": {"label": "Keep grinding (someone has to)", "effects": {"sanity": -4, "reputation": 5}, "hiddenConsequences": null, "roast": "Grinding while the team shrinks. You're doing 3 people's jobs for 1 person's TC."}, "rightOption": {"label": "Update your own resume (writing on the wall)", "effects": {"stability": -3, "sanity": 3, "reputation": -5}, "hiddenConsequences": null, "roast": "Updating your resume while the team shrinks. The writing is on the wall and you can actually read."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "life_manager_quits", "character": "Calendar", "scenario": "Your manager just accepted a role at Stripe. '**Couldn't say no to the TC.**' You now report to a director who manages 47 people and **doesn't know your name**. Orphaned.", "leftOption": {"label": "Introduce yourself to new manager", "effects": {"reputation": 3, "stability": -3, "tc": 3}, "hiddenConsequences": null, "roast": "Introducing yourself to the new manager. Time to re-explain your entire existence."}, "rightOption": {"label": "Fly under the radar (rest and vest opportunity)", "effects": {"sanity": 3, "stability": -5, "tc": -3}, "hiddenConsequences": [{"effects": {"reputation": -5}, "description": "New manager didn't know you existed until perf review. 'I don't have enough context to rate you.' Default rating: meets expectations. Refresher: $0.", "delay": 5}], "roast": "Flying under the radar after your manager quits. Rest and vest opportunity detected."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false, "excludes": ["blind_pip", "boost_good_review", "boost_spot_bonus", "credit_thief", "life_good_1on1", "meta_perf_rating", "ramp_feedback", "sr_new_manager", "sr_stack_rank"]}, {"id": "life_good_1on1", "character": "Manager", "scenario": "Rare: a **genuinely good 1:1**. Your manager asks how you're doing. Means it. Listens. Offers to block scope creep. Says '**your health matters more than the sprint.**' You almost cry.", "leftOption": {"label": "Open up honestly", "effects": {"sanity": 8, "stability": 3, "reputation": -3, "tc": 3}, "hiddenConsequences": null, "roast": "Opening up honestly in a 1:1. Brave, but anything you say can and will be used in your perf review."}, "rightOption": {"label": "\"I'm fine\" (walls up)", "effects": {"sanity": 3, "tc": -3}, "hiddenConsequences": null, "roast": "'I'm fine' in a 1:1. The walls are up and the TC keeps flowing."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "life_coffee_chat", "character": "Coworker", "scenario": "Random coffee chat with someone from another team. They're cool. **No agenda. No politics.** Just two humans talking about non-work things for 20 minutes. This is rarer than a good refresher grant.", "leftOption": {"label": "Make it a recurring thing", "effects": {"sanity": 5, "reputation": 3, "stability": -3}, "hiddenConsequences": null, "roast": "Making a coffee chat recurring. You just created a meeting. You've become what you swore to destroy."}, "rightOption": {"label": "Enjoy the moment, back to grind", "effects": {"sanity": 5, "tc": -3}, "hiddenConsequences": null, "roast": "Enjoying a single coffee chat and moving on. A moment of human connection in the corporate void."}, "minStage": "newHire", "maxStage": "contributing", "isTutorial": false}, {"id": "life_hackathon_fun", "character": "Team", "scenario": "Internal hackathon but your team actually builds something fun. Not an AI wrapper. A **Slack bot that roasts people's commit messages**. You laugh for the first time in weeks. It wins nothing. It wins everything.", "leftOption": {"label": "Deploy it to prod (chaotic good)", "effects": {"sanity": 8, "reputation": -5}, "hiddenConsequences": null, "roast": "Deploying a hackathon project to prod. Chaotic good energy, but oncall is going to hate you."}, "rightOption": {"label": "Keep it as a team inside joke", "effects": {"sanity": 5, "tc": -3}, "hiddenConsequences": null, "roast": "Keeping it as an inside joke. The best code is the code that never sees production."}, "minStage": "ramping", "maxStage": "senior", "isTutorial": false}, {"id": "badge_swiper", "character": "Security Dashboard", "scenario": "Your company tracks **badge swipes**. Your team has perfected '**coffee badging**' \u2014 swipe in, grab coffee, leave in 90 minutes. Your manager pulls you aside with a printout.", "leftOption": {"label": "Start actually staying", "effects": {"sanity": -7, "tc": 0, "reputation": 0, "stability": 5}, "hiddenConsequences": null, "roast": "Welcome to your new life of fluorescent lighting and small talk."}, "rightOption": {"label": "Perfect your coffee badge timing", "effects": {"sanity": 0, "tc": 0, "reputation": 3, "stability": -5}, "hiddenConsequences": [{"effects": {"sanity": 0, "tc": 0, "reputation": 0, "stability": -8}, "description": "HR sends a formal warning email about badge swipe patterns. Your manager is cc'd.", "delay": 4}], "roast": "90 minutes? Those are rookie numbers."}, "minStage": "newHire", "maxStage": null, "isTutorial": false}, {"id": "recursive_pip", "character": "Your Skip-Level", "scenario": "Your manager suddenly flips from praising you to marking you '**needs improvement.**' A teammate whispers: your manager is **on a PIP**. Their PIP project? PIP someone on their team.", "leftOption": {"label": "Confront your manager", "effects": {"sanity": 0, "tc": 0, "reputation": 5, "stability": -8}, "hiddenConsequences": null, "roast": "Bold move, Cotton."}, "rightOption": {"label": "Keep your head down", "effects": {"sanity": -4, "tc": 0, "reputation": 0, "stability": 3}, "hiddenConsequences": [{"effects": {"sanity": 0, "tc": 0, "reputation": 10, "stability": 0}, "description": "Your manager gets fired. New manager loves you \u2014 fresh start, clean slate.", "delay": 5}], "roast": "Survival mode: engaged."}, "minStage": "ramping", "maxStage": "senior", "isTutorial": false, "excludes": ["boost_good_review", "boost_spot_bonus", "life_good_1on1"]}, {"id": "leetcode_gauntlet", "character": "LinkedIn Recruiter", "scenario": "A recruiter DMs you about a role. Phone screen. Online assessment. **5 back-to-back interviews.** You pass everything. Then: **4 months of 'team match limbo.'** All your competing offers expire.", "leftOption": {"label": "Accept the lowball offer", "effects": {"sanity": -2, "tc": -8, "reputation": 0, "stability": 5}, "hiddenConsequences": null, "roast": "At least you have health insurance."}, "rightOption": {"label": "Walk away", "effects": {"sanity": 5, "tc": 0, "reputation": 3, "stability": -3}, "hiddenConsequences": null, "roast": "The recruiter will DM you again in 3 months."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "promo_treadmill", "character": "Promo Committee", "scenario": "You've been '**almost ready**' for 2 years. You led a massive cross-team project. It shipped. At promo committee: '**The project wasn't complex enough.**' They want you to do it again. But bigger.", "leftOption": {"label": "Keep grinding for promo", "effects": {"sanity": -8, "tc": -1, "reputation": 5, "stability": 0}, "hiddenConsequences": null, "roast": "The goalposts have been moved to a different stadium."}, "rightOption": {"label": "Lateral to another company at higher level", "effects": {"sanity": 3, "tc": 8, "reputation": 0, "stability": -5}, "hiddenConsequences": null, "roast": "The fastest way to get promoted is to leave."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false}, {"id": "quiet_firing", "character": "Your Calendar", "scenario": "You haven't been laid off. But your manager **moved you to a dead-end project**, stopped inviting you to planning meetings, and your 1:1s went from weekly to '**as needed.**'", "leftOption": {"label": "Confront your manager directly", "effects": {"sanity": 5, "tc": 0, "reputation": 0, "stability": -8}, "hiddenConsequences": null, "roast": "They'll deny everything. Professionally."}, "rightOption": {"label": "Take the hint and negotiate an exit", "effects": {"sanity": 0, "tc": 5, "reputation": 0, "stability": -5}, "hiddenConsequences": [{"effects": {"sanity": 0, "tc": 10, "reputation": 0, "stability": 0}, "description": "Severance package lands. Turns out they wanted you to leave \u2014 and they'll pay for it.", "delay": 3}], "roast": "The quiet part is getting louder."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false, "excludes": ["boost_good_review", "boost_spot_bonus", "life_good_1on1"]}, {"id": "ai_replacement_memo", "character": "CEO (All-Hands Email)", "scenario": "'Every team must demonstrate how **AI increases productivity by 40%** or face headcount review.' Your PM asks you to write a doc about how ChatGPT will replace... **you.**", "leftOption": {"label": "Write a convincing doc that protects your team", "effects": {"sanity": -7, "tc": 0, "reputation": 5, "stability": 0}, "hiddenConsequences": null, "roast": "You just automated yourself on paper."}, "rightOption": {"label": "Prove AI can't do your job", "effects": {"sanity": 0, "tc": 0, "reputation": -5, "stability": 8}, "hiddenConsequences": [{"effects": {"sanity": 0, "tc": 0, "reputation": 0, "stability": -10}, "description": "VP uses your doc to justify AI headcount reduction. Your team loses 3 heads.", "delay": 5}], "roast": "The AI can't do your job. But it costs less."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "pizza_party_layoffs", "character": "People & Culture Team", "scenario": "Your company just **laid off 15%**. The survivors are demoralized. Leadership's response: **2 pizzas, a foosball tournament**, and an email saying 'we're stronger together.'", "leftOption": {"label": "Attend and smile", "effects": {"sanity": -7, "tc": 0, "reputation": 0, "stability": 3}, "hiddenConsequences": null, "roast": "The pizza is cold. Like your company's empathy."}, "rightOption": {"label": "Skip and post on Blind", "effects": {"sanity": 0, "tc": 0, "reputation": 5, "stability": -3}, "hiddenConsequences": [{"effects": {"sanity": 0, "tc": 0, "reputation": 0, "stability": -8}, "description": "Your Blind post goes viral. HR launches an investigation into the leak.", "delay": 4}], "roast": "TC or GTFO has never felt more real."}, "minStage": "newHire", "maxStage": null, "isTutorial": false}, {"id": "alignment_tax", "character": "Staff Engineer", "scenario": "You want to ship a **2-week feature**. First: write a 1-pager. PM alignment. Design review. Security review. Legal review. Architecture review. VP sign-off. The process takes **6 weeks.**", "leftOption": {"label": "Follow the process", "effects": {"sanity": -8, "tc": -1, "reputation": -5, "stability": 5}, "hiddenConsequences": null, "roast": "Process is what happens when trust dies."}, "rightOption": {"label": "Just build it and ask forgiveness", "effects": {"sanity": 0, "tc": 0, "reputation": 8, "stability": -3}, "hiddenConsequences": null, "roast": "Move fast and break... processes."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false}, {"id": "credit_thief", "character": "Your Manager (Leadership Review)", "scenario": "You spent 3 months building a system that **saves $2M/year**. Your manager presents it **without mentioning your name**. 'Leadership knows it was a team effort.'", "leftOption": {"label": "Email leadership directly", "effects": {"sanity": 0, "tc": 0, "reputation": 8, "stability": -5}, "hiddenConsequences": [{"effects": {"sanity": 0, "tc": -10, "reputation": 0, "stability": 0}, "description": "Your manager retaliates. Perf review: 'needs improvement on collaboration.' Refresher grant: zero.", "delay": 5}], "roast": "Bold. Also career-limiting."}, "rightOption": {"label": "Let it go", "effects": {"sanity": -7, "tc": 0, "reputation": -5, "stability": 0}, "hiddenConsequences": null, "roast": "They'll credit you in the next reorg. By firing you."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false}, {"id": "empire_builder", "character": "Your Director", "scenario": "Your Director needs **20+ reports** for their VP promo. They pitch a new initiative requiring 15 new headcount. You know the project is **marginal**. But they want you to be tech lead.", "leftOption": {"label": "Take the tech lead role", "effects": {"sanity": -2, "tc": 8, "reputation": 5, "stability": 0}, "hiddenConsequences": [{"effects": {"sanity": 0, "tc": 0, "reputation": -8, "stability": -12}, "description": "Entire initiative gets cut in the next reorg. Your team is dissolved. Your Director got their VP title though.", "delay": 5}], "roast": "Empire building is just approved hoarding."}, "rightOption": {"label": "Stay on your current team", "effects": {"sanity": 0, "tc": -3, "reputation": 0, "stability": 5}, "hiddenConsequences": null, "roast": "The safe choice. How very... staff."}, "minStage": "staff", "maxStage": null, "isTutorial": false}, {"id": "overemployed_gambit", "character": "Your Conscience", "scenario": "Remote work. J1 is coasting mode. A recruiter offers J2, fully remote. You do the math: you could **double your TC**. Your calendar management becomes your most important skill.", "leftOption": {"label": "Take J2", "effects": {"sanity": -4, "tc": 8, "reputation": 4, "stability": -5}, "hiddenConsequences": [{"effects": {"sanity": 0, "tc": 0, "reputation": -10, "stability": -15}, "description": "You got caught. Both companies fire you. LinkedIn is a minefield.", "delay": 5}], "roast": "Two standups. Two sprint plannings. One you."}, "rightOption": {"label": "Stay honest", "effects": {"sanity": 5, "tc": 0, "reputation": -3, "stability": 0}, "hiddenConsequences": null, "roast": "Your integrity can't be vested."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false}, {"id": "bait_switch_role", "character": "HR (Surprise Meeting)", "scenario": "You were hired to build a **new distributed system**. 3 months in, project cancelled. You're reassigned to maintain a **legacy CRUD app**. 'We need flexible engineers.'", "leftOption": {"label": "Embrace the new role", "effects": {"sanity": -8, "tc": -1, "reputation": 0, "stability": 8}, "hiddenConsequences": null, "roast": "Flexibility is what they call it when they break you."}, "rightOption": {"label": "Demand a transfer or leave", "effects": {"sanity": 5, "tc": 3, "reputation": 0, "stability": -8}, "hiddenConsequences": null, "roast": "The exit interview will be the most honest conversation you've had."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false}, {"id": "jargon_avalanche", "character": "VP (Email)", "scenario": "'We need to **synergize our bandwidth** to circle back on the deliverables and **move the needle** on our north star metric. Let's take this offline and ideate on low-hanging fruit.'", "leftOption": {"label": "Ask for clarification", "effects": {"sanity": 0, "tc": 3, "reputation": -5, "stability": 0}, "hiddenConsequences": null, "roast": "You'll be labeled 'not a self-starter.'"}, "rightOption": {"label": "Guess and build something", "effects": {"sanity": -2, "tc": 0, "reputation": 5, "stability": 0}, "hiddenConsequences": [{"effects": {"sanity": -8, "tc": 0, "reputation": 0, "stability": 0}, "description": "Wrong guess. VP wanted the opposite. Rebuild everything from scratch.", "delay": 4}], "roast": "You understood none of that. Neither did they."}, "minStage": "newHire", "maxStage": null, "isTutorial": false}, {"id": "were_a_family", "character": "CEO (All-Hands)", "scenario": "'**We're not just a company, we're a family.**' Two weeks later, they **lay off your teammate** who just had a baby. Slack #general explodes. HR posts a reminder about the 'respectful communication policy.'", "leftOption": {"label": "Post something supportive in Slack", "effects": {"sanity": 0, "tc": 0, "reputation": 5, "stability": -3}, "hiddenConsequences": null, "roast": "Your heart emoji really moved the needle."}, "rightOption": {"label": "Stay quiet and update your resume", "effects": {"sanity": -4, "tc": 0, "reputation": 0, "stability": 3}, "hiddenConsequences": null, "roast": "Silence is complicity. Also survival."}, "minStage": "newHire", "maxStage": null, "isTutorial": false}, {"id": "backdoor_reference", "character": "Unknown Caller", "scenario": "You're interviewing at a competitor. The recruiter '**happens to know**' someone at your current company. Monday morning, your **access to sensitive repos is revoked.**", "leftOption": {"label": "Deny everything", "effects": {"sanity": -4, "tc": 3, "reputation": 0, "stability": -8}, "hiddenConsequences": null, "roast": "The access logs tell a different story."}, "rightOption": {"label": "Accelerate your departure", "effects": {"sanity": 0, "tc": -5, "reputation": 0, "stability": 5}, "hiddenConsequences": [{"effects": {"sanity": 0, "tc": 10, "reputation": 0, "stability": 0}, "description": "New company offers a signing bonus to close you faster. Sometimes burning bridges lights the way.", "delay": 3}], "roast": "The fastest two weeks' notice in history."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "amazon_rto_mandate", "character": "Andy Jassy (All-Hands)", "scenario": "Amazon mandates **5 days in-office**. Your entire team was hired remote during COVID. **Three people quit on the spot.** Jassy says it's about 'strengthening culture.' Blind is nuclear. Your lease renewal is next month.", "leftOption": {"label": "Relocate to Seattle (RIP your life)", "effects": {"tc": -5, "sanity": -4, "stability": 8}, "hiddenConsequences": null, "roast": "Relocating to Seattle because a billionaire said vibes are better in person. Your rent just doubled."}, "rightOption": {"label": "Refuse and dare them to fire you", "effects": {"sanity": 8, "stability": -8}, "hiddenConsequences": [{"effects": {"tc": 10}, "description": "They didn't fire you \u2014 they put you on a 'voluntary resignation' list with enhanced severance. You took the package. Blind calls this a 'W.'", "delay": 4}], "roast": "Playing chicken with Amazon's RTO policy. Bold strategy for someone with unvested RSUs."}, "minStage": "ramping", "maxStage": null, "isTutorial": false, "excludes": ["blind_rto_mandate"]}, {"id": "amazon_lp_interview", "character": "Bar Raiser", "scenario": "You're bar-raising an internal transfer. The candidate gives a **perfect STAR answer**. Too perfect. You realize they're reciting from the internal LP interview prep doc that **got leaked on Blind** last month. You wrote that doc.", "leftOption": {"label": "Incline anyway (they did the work)", "effects": {"reputation": -3, "sanity": 5}, "hiddenConsequences": null, "roast": "Passing someone who memorized your leaked doc. The circle of Amazon life."}, "rightOption": {"label": "Go off-script with a curveball LP question", "effects": {"reputation": 5, "sanity": -2}, "hiddenConsequences": [{"effects": {"reputation": -5}, "description": "The candidate complained to HR that your question was 'unfair and not in the LP framework.' HR agreed. You're banned from bar-raising for a quarter.", "delay": 3}], "roast": "Going off-script in an Amazon interview. The LPs are scripture, not guidelines."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false}, {"id": "amazon_frugality", "character": "Amazon Finance", "scenario": "Your team needs a **$200 software license** to unblock a launch. Finance rejects it citing the **Frugality LP**. Your team's annual revenue impact is $40M. The approval chain has 6 VPs. Someone suggests just expensing it as 'team snacks.'", "leftOption": {"label": "Expense it as snacks", "effects": {"sanity": 5, "stability": -3}, "hiddenConsequences": [{"effects": {"stability": -8}, "description": "Finance flagged the $200 'snack' receipt. You're now in an ethics review for expense fraud. Over a software license. At a trillion-dollar company.", "delay": 5}], "roast": "Expensing software as snacks. Creative accounting meets career suicide."}, "rightOption": {"label": "Wait 6 weeks for proper approval", "effects": {"sanity": -4, "reputation": -3}, "hiddenConsequences": null, "roast": "Waiting 6 weeks for a $200 license at a trillion-dollar company. Frugality is a lifestyle."}, "minStage": "ramping", "maxStage": "senior", "isTutorial": false}, {"id": "google_layoffs_googleyness", "character": "Sundar (All-Hands)", "scenario": "Google lays off **12,000 people**. Some found out when their **badge stopped working**. The all-hands Q&A is 90% softball questions pre-screened by comms. Someone asks about Googleyness being removed from perf reviews. Sundar pivots to talking about AI.", "leftOption": {"label": "Ask the real question on Dory", "effects": {"sanity": 5, "reputation": -5}, "hiddenConsequences": null, "roast": "Asking a real question at a Google all-hands. Your Dory upvotes won't save you from the next round."}, "rightOption": {"label": "Keep your head down and ship", "effects": {"sanity": -4, "stability": 5}, "hiddenConsequences": null, "roast": "Head down, ship code, survive the layoff. The new Google culture is just regular corporate with free lunch."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "google_20_percent", "character": "Google PM", "scenario": "You spent your '20% time' building an internal tool that **3,000 Googlers use daily**. Your manager says it **doesn't count for perf** because it's not on your team's OKRs. Gmail was a 20% project. Yours gets deprecated.", "leftOption": {"label": "Kill the project and focus on OKRs", "effects": {"sanity": -4, "reputation": 5}, "hiddenConsequences": [{"effects": {"sanity": -5}, "description": "3,000 Googlers are now angry that your tool is gone. Someone rebuilt it worse. They got promoted for it. This is the circle of Google life.", "delay": 4}], "roast": "Killing a tool 3,000 people use because it's not on your OKRs. Google in a nutshell."}, "rightOption": {"label": "Transfer to the team that would own it", "effects": {"stability": -3, "tc": -3}, "hiddenConsequences": null, "roast": "Transferring teams to chase your own side project. Google lets you do this. That's the trap."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false}, {"id": "google_memegen", "character": "Memegen", "scenario": "Your meme about the latest reorg got **2,000 upvotes on Memegen**. It featured your VP's face on a sinking ship. HR says 'it's not a violation per se, but...' Your VP's EA scheduled a 1:1 with **no agenda.** Your TL is not making eye contact.", "leftOption": {"label": "Delete it and apologize", "effects": {"sanity": -2, "stability": 5}, "hiddenConsequences": null, "roast": "Deleting a viral meme. The internet never forgets, and neither does your VP."}, "rightOption": {"label": "Double down with a sequel meme", "effects": {"sanity": 8, "reputation": 5, "stability": -8}, "hiddenConsequences": [{"effects": {"stability": -5, "reputation": 8}, "description": "The sequel meme went even more viral. You're now a folk hero. Your VP was quietly reorged out. Correlation? Nobody can prove it. Memegen is undefeated.", "delay": 5}], "roast": "Doubling down on Memegen. Either you're getting promoted or fired. No middle ground."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "meta_year_of_efficiency", "character": "Meta HR", "scenario": "It's the '**Year of Efficiency.**' 11,000 people got cut. You survived. Your team went from **12 to 4**. You now own three services you've never seen before. Your manager says 'this is a growth opportunity.' The on-call rotation is now just you.", "leftOption": {"label": "Embrace the chaos (resume padding)", "effects": {"sanity": -7, "reputation": 8}, "hiddenConsequences": [{"effects": {"sanity": -5}, "description": "You now own 3 services, 2 oncall rotations, and 0 documentation. A SEV-1 hits at 2 AM on a service you've never deployed. Welcome to efficiency.", "delay": 3}], "roast": "Calling layoff survivor guilt a 'growth opportunity.' Your manager is gaslighting at scale."}, "rightOption": {"label": "Negotiate for the laid-off people's RSUs", "effects": {"tc": 5, "reputation": -5}, "hiddenConsequences": null, "roast": "Asking for dead people's RSUs. Cold-blooded, but this is Meta. Zuck would respect it."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "meta_metamates", "character": "Internal Comms", "scenario": "The company values just changed. You are no longer 'employees.' You are '**Metamates.**' The internal post has **3,000 sad reacts.** Someone made a 'Metamates' Slack emoji of a sinking ship. The Blind thread has 500 comments, all unhinged.", "leftOption": {"label": "Use 'Metamates' unironically in meetings", "effects": {"reputation": 5, "sanity": -4}, "hiddenConsequences": null, "roast": "Saying 'Metamates' with a straight face. Your soul left your body but your stock is vesting."}, "rightOption": {"label": "Post the pirate ship emoji in every Slack channel", "effects": {"sanity": 8, "reputation": -3}, "hiddenConsequences": [{"effects": {"reputation": 5}, "description": "The pirate ship emoji became the unofficial team mascot. Even your skip-level uses it. Sometimes resistance becomes culture.", "delay": 3}], "roast": "Protesting corporate cringe with emojis. This is what rebellion looks like at $400K TC."}, "minStage": "newHire", "maxStage": null, "isTutorial": false}, {"id": "meta_reality_labs", "character": "Reality Labs PM", "scenario": "You got reorged into **Reality Labs**. The division has burned **$50B and counting**. Your project is a VR meeting room that nobody uses. Zuck demoed your feature wearing the headset backward. The stock dropped 4% that day.", "leftOption": {"label": "Request transfer back to ads (the money printer)", "effects": {"stability": -3, "tc": 5}, "hiddenConsequences": null, "roast": "Escaping Reality Labs for ads. Going from burning money to printing it."}, "rightOption": {"label": "Lean in \u2014 maybe VR will be big someday", "effects": {"sanity": -4, "stability": 5}, "hiddenConsequences": [{"effects": {"tc": -8}, "description": "Reality Labs budget got slashed again. Your team is now 'AI-powered VR.' Same product, new buzzword. Your refresher was 60% below band.", "delay": 4}], "roast": "Believing in the metaverse in 2024. Either you're a visionary or you're trapped. Probably trapped."}, "minStage": "contributing", "maxStage": null, "isTutorial": false}, {"id": "microsoft_teams_meeting", "character": "Outlook Calendar", "scenario": "Your calendar is a **solid wall of blue**. Back-to-back Teams meetings from 9 AM to 6 PM. No gaps. Your manager just added a 'quick sync' over your only bathroom break. **You haven't written code in 3 days.**", "leftOption": {"label": "Decline all and go heads-down", "effects": {"sanity": 7, "reputation": -5}, "hiddenConsequences": null, "roast": "Declining meetings at Microsoft is like refusing oxygen on a submarine. Bold, but probably fatal."}, "rightOption": {"label": "Accept your fate as a meeting NPC", "effects": {"sanity": -5, "stability": 5}, "hiddenConsequences": null, "roast": "Nine hours of Teams meetings and zero lines of code. This is what L62 looks like."}, "minStage": "contributing", "maxStage": null, "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "microsoft_growth_mindset", "character": "Manager (Connect Review)", "scenario": "Your Connect feedback says '**show more growth mindset.**' You've been 'growing' for 3 years. Still **L62**. Your skip-level's feedback is identical, word for word. It's a template.", "leftOption": {"label": "Write a growth mindset essay in your self-review", "effects": {"reputation": 5, "sanity": -5}, "hiddenConsequences": [{"effects": {"tc": 4}, "description": "Your growth mindset essay was so compelling they used it as a template for the whole org. You got a 'Culture Champion' award. No promo though.", "delay": 4}], "roast": "Writing corporate fan fiction about your own development. Satya would shed a single tear."}, "rightOption": {"label": "Ask point-blank what L63 actually requires", "effects": {"reputation": -4, "sanity": 5}, "hiddenConsequences": null, "roast": "Asking for concrete promo criteria at Microsoft. You sweet summer child."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "microsoft_azure_war", "character": "CVP (All-Hands)", "scenario": "AWS just launched the **exact feature** your Azure team has been building for 18 months. Leadership says '**stay the course.**' The Blind thread is titled 'Azure is cooked.' Your PM is updating the roadmap to add AI to it.", "leftOption": {"label": "Pivot to AI buzzwords and ship fast", "effects": {"tc": 5, "sanity": -3}, "hiddenConsequences": null, "roast": "Slapping 'AI-powered' on a feature AWS shipped last year. The Microsoft way."}, "rightOption": {"label": "Write a brutally honest strategy doc", "effects": {"reputation": -6, "sanity": 5}, "hiddenConsequences": [{"effects": {"reputation": 8}, "description": "Your strategy doc got forwarded up to Satya's staff. They killed the project and moved the team to Copilot. You accidentally got a promo for 'strategic thinking.'", "delay": 5}], "roast": "Writing honest strategy docs at a company that spent $26B on LinkedIn. Brave."}, "minStage": "senior", "maxStage": null, "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "microsoft_reorg", "character": "VP Email (6 AM Monday)", "scenario": "Third **reorg in 2 years**. Your skip-level is now your peer. Your peer is now your skip-level. **Same desks, same product, new org chart.** The email calls it 'aligning for the next wave of AI.' Morale is a concept.", "leftOption": {"label": "Embrace the new structure enthusiastically", "effects": {"stability": 5, "sanity": -4}, "hiddenConsequences": null, "roast": "Celebrating your third reorg like it's a fresh start. That's not resilience, that's dissociation."}, "rightOption": {"label": "Start interviewing at Google", "effects": {"sanity": 6, "stability": -4}, "hiddenConsequences": null, "roast": "Leaving Microsoft's reorg chaos for Google's reorg chaos. Lateral move at best."}, "minStage": "contributing", "maxStage": null, "isTutorial": false, "excludes": ["boost_offsite", "contrib_team_exodus", "life_hackathon_fun"], "campaignFields": null}, {"id": "microsoft_stack_rank", "character": "Anonymous Colleague", "scenario": "Stack ranking is '**officially dead.**' Your manager still ranks the team in a **secret spreadsheet**. A colleague found it on SharePoint. You're #7 out of 8. The person below you just joined last month.", "leftOption": {"label": "Confront your manager about the spreadsheet", "effects": {"reputation": -5, "sanity": 6}, "hiddenConsequences": null, "roast": "Confronting your manager with evidence of secret rankings. HR is already drafting your PIP."}, "rightOption": {"label": "Grind silently to move up the secret list", "effects": {"sanity": -4, "tc": 4}, "hiddenConsequences": null, "roast": "Optimizing for a ranking system that doesn't officially exist. Peak Microsoft energy."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "tiktok_ban_anxiety", "character": "Lark Group Chat", "scenario": "Congress is voting on the **TikTok ban** again. Your equity might be **worthless by Friday**. Lark is buzzing with panic. Legal sent a 'don't talk to press' email. Your parents keep texting '**are you okay??**' You are not okay.", "leftOption": {"label": "Start quietly interviewing at Meta", "effects": {"stability": -4, "tc": 5}, "hiddenConsequences": null, "roast": "Jumping from the company Congress wants to ban to the one Congress wants to break up. Lateral move."}, "rightOption": {"label": "Diamond hands \u2014 ride it out for the equity", "effects": {"sanity": -5, "tc": 4}, "hiddenConsequences": [{"effects": {"tc": -8}, "description": "The ban passed committee. ByteDance announced a 'restructuring' of US equity. Your options are now denominated in vibes.", "delay": 5}], "roast": "Holding TikTok equity through a congressional ban vote. That's not conviction, that's denial."}, "minStage": "contributing", "maxStage": null, "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "tiktok_996", "character": "Beijing Team Lead (Lark)", "scenario": "The Beijing team shipped features at **2 AM your time**. Your PR has **47 comments by morning**. All in Mandarin. Google Translate says one comment is 'this code is garbage.' Another says 'please fix before EOD **Beijing time**.' That's 4 hours ago.", "leftOption": {"label": "Pull an all-nighter to match Beijing pace", "effects": {"sanity": -6, "reputation": 6}, "hiddenConsequences": null, "roast": "Working 996 hours from a US time zone. You're not even getting the 996 pay bump."}, "rightOption": {"label": "Reply during US business hours only", "effects": {"sanity": 5, "reputation": -5}, "hiddenConsequences": null, "roast": "Setting boundaries with a team that doesn't have a word for boundaries. Good luck."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "tiktok_algorithm", "character": "Cafeteria Badge Scanner", "scenario": "The **algorithm team** gets a dedicated cafeteria, private gym, and catered dinner. Your team gets **vending machines** and a microwave that smells like fish. Same company. Same building. Different caste system.", "leftOption": {"label": "Request a transfer to the algorithm team", "effects": {"tc": 4, "stability": -5}, "hiddenConsequences": null, "roast": "Trying to join the algorithm team for the food. At least your priorities are honest."}, "rightOption": {"label": "Organize a petition for equal cafeteria access", "effects": {"sanity": 5, "reputation": -4}, "hiddenConsequences": null, "roast": "Starting a cafeteria equality movement at a company owned by ByteDance. Choose your battles."}, "minStage": "ramping", "maxStage": null, "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "tiktok_lark", "character": "Manager (Lark DM, 11:14 PM)", "scenario": "Your manager sends a Lark message at **11 PM**: '**Quick question.**' It's never quick. You open it. It's a screenshot of a dashboard with a red arrow and '**why is this down 2%?**' The answer is Saturday traffic. It's always Saturday traffic.", "leftOption": {"label": "Reply immediately with a detailed analysis", "effects": {"reputation": 5, "sanity": -5}, "hiddenConsequences": null, "roast": "Writing a metrics analysis at 11 PM because your manager doesn't understand weekends. Peak TikTok."}, "rightOption": {"label": "Reply in the morning: 'Weekend traffic pattern'", "effects": {"sanity": 5, "reputation": -4}, "hiddenConsequences": null, "roast": "Making your manager wait 8 hours for an answer they could've Googled. Boundaries are beautiful."}, "minStage": "contributing", "maxStage": null, "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "tiktok_parent_company", "character": "US Product Manager", "scenario": "ByteDance leadership **overrides your roadmap** from Beijing. Your US PM finds out on Lark, not in the meeting. The new priority is a feature that makes **zero sense** for US users. Your PM is writing a 'strategy alignment' doc. It's a cope doc.", "leftOption": {"label": "Build what Beijing wants, ship fast", "effects": {"stability": 6, "sanity": -4}, "hiddenConsequences": null, "roast": "Building features for a market you don't understand because someone in Beijing said so. Welcome to TikTok."}, "rightOption": {"label": "Push back with US market data", "effects": {"sanity": 5, "stability": -6}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "Your pushback was 'noted' in Beijing. Noted means ignored. The feature shipped anyway. Your PM quit. You're now the de facto PM.", "delay": 4}], "roast": "Presenting US market data to ByteDance leadership. That's not strategy, that's a suggestion box with extra steps."}, "minStage": "senior", "maxStage": null, "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "balance_tc_signing_bonus", "character": "Fidelity App", "scenario": "Signing bonus hits your account. **$50K.** You refresh Fidelity every 4 minutes. Your net worth just jumped more than your parents made in a year. You start googling 'fiduciary advisor under 30.'", "leftOption": {"label": "Max out your 401k immediately", "effects": {"tc": 5, "sanity": 3, "reputation": -3, "stability": 3}, "hiddenConsequences": null, "roast": "Maxing your 401k on Day 30. You'll be rich at 65 and miserable at 26. Priorities."}, "rightOption": {"label": "Treat yourself (you earned it?)", "effects": {"tc": 8, "sanity": 5, "reputation": 0, "stability": -3}, "hiddenConsequences": null, "roast": "$50K signing bonus and you bought a Herman Miller for your apartment. You're becoming them."}, "minStage": "newHire", "maxStage": "ramping", "isTutorial": false}, {"id": "balance_tc_rsu_cliff", "character": "E*Trade", "scenario": "Your RSU cliff just hit. You are now **obscenely wealthy on paper**. Your Zillow searches have changed zip codes. You check your portfolio during standups. Your identity is now your net worth.", "leftOption": {"label": "Start tax-loss harvesting like a real adult", "effects": {"tc": 8, "sanity": -2, "reputation": 2}, "hiddenConsequences": null, "roast": "Tax-loss harvesting your RSUs. You're one spreadsheet away from becoming a finance bro."}, "rightOption": {"label": "Diversify immediately (paper gains aren't real)", "effects": {"tc": 5, "sanity": 3, "stability": -3}, "hiddenConsequences": null, "roast": "Selling your RSUs the day they vest. Smart financially, but your loyalty metric just tanked."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false}, {"id": "balance_stability_comfort_trap", "character": "Your Calendar", "scenario": "Same desk. Same standup. Same sprint. You haven't learned anything new in **6 months**. But the paycheck is reliable. Your commits are auto-approved. You could do this forever. That's the problem.", "leftOption": {"label": "Lean into the comfort (rest and vest)", "effects": {"stability": 8, "sanity": 3, "reputation": -3, "tc": 3}, "hiddenConsequences": null, "roast": "Leaning into comfort. You're not resting and vesting, you're professionally decomposing."}, "rightOption": {"label": "Stay the course (why rock the boat?)", "effects": {"stability": 8, "sanity": -2, "tc": -3}, "hiddenConsequences": null, "roast": "Staying the course because change is scary. Your comfort zone has a moat and a drawbridge."}, "minStage": "contributing", "maxStage": "senior", "isTutorial": false}, {"id": "balance_stability_autopilot", "character": "Your Brain", "scenario": "You could do this job **in your sleep**. You basically are. Your standup updates are copy-paste from yesterday. Nobody's complained. Nobody's noticed. You're a ghost with direct deposit.", "leftOption": {"label": "Volunteer for a stretch project", "effects": {"sanity": -4, "reputation": 5, "stability": -3}, "hiddenConsequences": null, "roast": "Volunteering for a stretch project. Your autopilot just got cancelled mid-flight."}, "rightOption": {"label": "Keep coasting (the dream, right?)", "effects": {"stability": 8, "sanity": -4}, "hiddenConsequences": null, "roast": "Coasting so hard your career has cruise control. This is the dream until it's the nightmare."}, "minStage": "senior", "maxStage": null, "isTutorial": false}, {"id": "balance_tc_stock_split", "character": "CNBC Alert", "scenario": "Company stock splits. Your portfolio just **doubled on paper**. You can't sell for 2 years. Your net worth is theoretical but your ego is very real. You start saying 'my position' unironically.", "leftOption": {"label": "Diamond hands (hold everything)", "effects": {"tc": 8, "stability": 3, "sanity": -2}, "hiddenConsequences": null, "roast": "Diamond hands on company stock. You're one earnings miss away from learning about concentration risk."}, "rightOption": {"label": "Collar strategy (hedge like a grown-up)", "effects": {"tc": 8, "sanity": -2}, "hiddenConsequences": null, "roast": "Hedging your company stock with a collar. You learned that word from a Reddit thread 3 hours ago."}, "minStage": "staff", "maxStage": null, "isTutorial": false}, {"id": "balance_layoff_day30", "character": "CEO (Zoom)", "scenario": "Day 30. Company-wide Zoom. CEO's face is wrong. '**We're making some difficult decisions.**' Your badge stops working at 2pm. Your Slack goes gray. You never even finished onboarding.", "leftOption": {"label": "Ask if there's any way to stay", "effects": {"stability": -8, "sanity": -4, "reputation": 3, "tc": -2}, "hiddenConsequences": null, "roast": "Last in, first out. Your desk was warm for exactly one sprint."}, "rightOption": {"label": "Start packing immediately", "effects": {"stability": -8, "reputation": -3, "sanity": -2}, "hiddenConsequences": null, "roast": "Last in, first out. Your desk was warm for exactly one sprint."}, "minStage": "newHire", "maxStage": "newHire", "isTutorial": false}, {"id": "balance_layoff_reorg", "character": "Your Manager", "scenario": "Reorg email drops. Your team **doesn't exist anymore**. Your manager says '**we're figuring it out**' but won't make eye contact. Your project is cancelled. Your code will never ship. You are overhead now.", "leftOption": {"label": "Network furiously for a new team", "effects": {"stability": -8, "sanity": -2}, "hiddenConsequences": null, "roast": "Networking for survival after a reorg. You're speed-dating teams like it's musical chairs. Because it is."}, "rightOption": {"label": "Wait for placement (trust the process)", "effects": {"stability": -5, "sanity": -4, "tc": 3}, "hiddenConsequences": null, "roast": "Trusting the process during a reorg. The process is what got your team deleted."}, "minStage": "ramping", "maxStage": "ramping", "isTutorial": false, "excludes": ["boost_offsite", "contrib_team_exodus", "life_hackathon_fun"]}, {"id": "balance_layoff_budget_cut", "character": "HR", "scenario": "Hiring freeze turns into a **headcount reduction**. You're the most recent hire on the team. Math is math. HR sends a calendar invite with no description. Your manager is suspiciously nice today.", "leftOption": {"label": "Prepare your case for why you're essential", "effects": {"stability": -5, "sanity": -7, "reputation": 3}, "hiddenConsequences": null, "roast": "Preparing a case for why you're essential. You've been here 2 months. Your case is a Post-it note."}, "rightOption": {"label": "Accept the inevitable", "effects": {"stability": -8, "sanity": -3, "reputation": 3}, "hiddenConsequences": null, "roast": "Accepting the layoff with grace. At least your severance covers 2 weeks of DoorDash."}, "minStage": "newHire", "maxStage": "ramping", "isTutorial": false}, {"id": "real_zoom_strangers", "character": "HR (Unknown)", "scenario": "Two people you've never met join your Zoom. **'We're here to discuss your role going forward.'** Your manager is conspicuously absent.", "leftOption": {"label": "Demand your manager join", "effects": {"sanity": 2, "reputation": -1, "stability": -3}, "hiddenConsequences": null, "roast": "You demanded your manager join. They 'had a conflict.' The conflict was knowing what's about to happen and not wanting to watch."}, "rightOption": {"label": "Hear them out", "effects": {"sanity": -3, "stability": -3}, "hiddenConsequences": null, "roast": "You sat there and took it like a professional. The two strangers will forget your name by lunch. You'll remember theirs forever."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "real_sleeping_bag", "character": "Your VP", "scenario": "Your VP posts a photo of you sleeping at your desk at 2am. **'This is what dedication looks like.'** You haven't seen your apartment in 3 days.", "leftOption": {"label": "Set a boundary", "effects": {"sanity": 3, "reputation": -3}, "hiddenConsequences": null, "roast": "You set a boundary at a company that measures commitment in overnight commits. Your next perf review will mention 'work ethic concerns.'"}, "rightOption": {"label": "Lean into the grind", "effects": {"sanity": -3, "reputation": 3}, "hiddenConsequences": [{"effects": {"stability": -5}, "description": "The VP got promoted. You got a stress fracture and a $47 DoorDash habit. Your 'dedication' was never mentioned in the promo packet.", "delay": 4}], "roast": "You leaned in so hard you're horizontal. The VP screenshot is now their LinkedIn banner. You're not tagged."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "real_ghost_friends", "character": "Your Phone", "scenario": "Two weeks since the layoff. You text your closest work friend. No reply. Another: **'Seen.'** A third: **'Sorry, things are crazy.'** Nobody comes to your happy hour.", "leftOption": {"label": "Stop reaching out", "effects": {"sanity": -3}, "hiddenConsequences": null, "roast": "You learned the hardest lesson in tech: your work friends were work friends. The Slack DMs were the relationship. Without the green dot, you don't exist."}, "rightOption": {"label": "Keep trying", "effects": {"sanity": -2, "reputation": -2}, "hiddenConsequences": null, "roast": "You kept texting people who have survivor's guilt and a new sprint to worry about. You're a reminder of what could happen to them. Nobody wants that energy at brunch."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "real_golden_handcuffs", "character": "Your Spreadsheet", "scenario": "RSUs worth **$400K**. Don't vest for 2 more years. You hate your team. A startup you love offers **30% less**. Swipe to decide your freedom.", "leftOption": {"label": "Stay and vest", "effects": {"tc": 5, "sanity": -5}, "hiddenConsequences": null, "roast": "You chose the money. The spreadsheet won. In 2 years you'll have $400K and a therapist bill that eats half of it. But hey, the numbers worked out."}, "rightOption": {"label": "Take the pay cut", "effects": {"tc": -5, "sanity": 5}, "hiddenConsequences": null, "roast": "You left $400K on the table for 'fulfillment.' Your future self will either thank you or haunt you. Probably both, on alternating Mondays."}, "minStage": "senior", "maxStage": "staff", "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "real_rto_trap", "character": "CEO (All-Hands)", "scenario": "**5-day RTO mandate.** You moved 3 hours away during COVID. A survey leaked: 25% of execs admitted RTO was designed to make people quit.", "leftOption": {"label": "Comply and commute", "effects": {"sanity": -5, "stability": 3}, "hiddenConsequences": null, "roast": "6 hours a day in the car so you can sit in an open office on Zoom calls with people in other offices. Peak corporate efficiency."}, "rightOption": {"label": "Refuse and call their bluff", "effects": {"stability": -5, "sanity": 3}, "hiddenConsequences": [{"effects": {"tc": 3}, "description": "They blinked. Quietly approved your remote exception. Turns out the mandate was for the people they wanted to leave. You weren't one of them. This time.", "delay": 3}], "roast": "You called the bluff of a Fortune 500 CEO. Either you're brave or you have 12 months of savings. Hopefully both."}, "minStage": "contributing", "maxStage": "staff", "isTutorial": false, "excludes": null, "campaignFields": null}, {"id": "real_interview_ghost", "character": "Recruiter", "scenario": "**6 rounds.** Take-home project. 'Culture chat' with the founder. 3 weeks of silence. You check the posting. **It's been relisted.**", "leftOption": {"label": "Send a follow-up", "effects": {"sanity": -2, "reputation": 1}, "hiddenConsequences": null, "roast": "You sent a polite follow-up to a recruiter who ghosted you after making you whiteboard for 12 hours. They'll reply in 6 months asking if you're 'still looking.'"}, "rightOption": {"label": "Move on, never look back", "effects": {"sanity": 2}, "hiddenConsequences": null, "roast": "You walked away from a company that made you do 6 rounds and a take-home. The take-home is now in their codebase. Unpaid labor with extra steps."}, "minStage": "ramping", "maxStage": "senior", "isTutorial": false, "excludes": null, "campaignFields": null}];

const DEATH_SCREENS = {"sanityLow": {"title": "Burnout", "description": "You mass-replied 'per my last email' to the entire company. Security escorted you out. Your Blind post about it got 2,000 upvotes."}, "sanityHigh": {"title": "Enlightenment", "description": "You've achieved total clarity. You stood up in standup and said 'none of this matters.' You were right. You were also fired."}, "tcLow": {"title": "Broke", "description": "You can't afford the city you work in. You're living in your car in the office parking lot. HR noticed."}, "tcHigh": {"title": "Golden Handcuffs", "description": "Your TC is so high you golden-handcuffed yourself into a job you despise for 6 more years. You never leave. You never live."}, "reputationLow": {"title": "Invisible", "description": "Nobody remembers your name. When layoffs hit, your manager had to Google who you were."}, "reputationHigh": {"title": "Target", "description": "You're so visible the CEO knows your name. That's never good. You're now personally responsible for the next reorg."}, "stabilityLow": {"title": "Laid Off", "description": "Friday 4:47 PM. Calendar invite: 'Quick Chat with HR.' No agenda. Your badge stops working on Monday."}, "stabilityHigh": {"title": "Trapped", "description": "You're so essential they cancelled your PTO, your transfer request, and your resignation. You are the company now. The company is you."}};

